import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum StemType {
  VOCALS = 'VOCALS',
  DRUMS = 'DRUMS',
  BASS = 'BASS',
  SYNTH = 'SYNTH',
  PADS = 'PADS'
}

export interface SongStructure {
  title: string;
  bpm: number;
  key: string;
  genre: string;
  lyrics: {
    verse: string;
    chorus: string;
    bridge: string;
  };
  stems: Array<{
    type: StemType;
    description: string;
    intensity: number; // 0 to 1
  }>;
}

export interface AudioTrack {
  id: string;
  name: string;
  type: StemType;
  buffer?: AudioBuffer;
  volume: number;
  isMuted: boolean;
  isSolo: boolean;
  color: string;
}

export interface ProjectState {
  song?: SongStructure;
  tracks: AudioTrack[];
  isPlaying: boolean;
  currentTime: number;
}

import React from 'react';
import { Mic, Drum, Speaker, Music, Activity } from 'lucide-react';
import { StemType } from './types';

export const STEM_CONFIG = {
  [StemType.VOCALS]: { color: '#ec4899', icon: <Mic size={18} /> },
  [StemType.DRUMS]: { color: '#3b82f6', icon: <Drum size={18} /> },
  [StemType.BASS]: { color: '#f59e0b', icon: <Speaker size={18} /> },
  [StemType.SYNTH]: { color: '#10b981', icon: <Music size={18} /> },
  [StemType.PADS]: { color: '#8b5cf6', icon: <Activity size={18} /> },
};

export const INITIAL_TRACKS = [
  { id: '1', name: 'Lead Vocals', type: StemType.VOCALS, volume: 0.8, isMuted: false, isSolo: false, color: STEM_CONFIG[StemType.VOCALS].color },
  { id: '2', name: 'Drums', type: StemType.DRUMS, volume: 0.7, isMuted: false, isSolo: false, color: STEM_CONFIG[StemType.DRUMS].color },
  { id: '3', name: 'Bassline', type: StemType.BASS, volume: 0.6, isMuted: false, isSolo: false, color: STEM_CONFIG[StemType.BASS].color },
  { id: '4', name: 'Synthesis', type: StemType.SYNTH, volume: 0.5, isMuted: false, isSolo: false, color: STEM_CONFIG[StemType.SYNTH].color },
];

import { GoogleGenAI, Type } from "@google/genai";
import { SongStructure, StemType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateSongStructure = async (prompt: string): Promise<SongStructure> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate a detailed music production plan based on this idea: "${prompt}". 
    Return a structured JSON object including title, lyrics (verse, chorus, bridge), genre, BPM, key, 
    and a set of stems (Vocals, Drums, Bass, Synth, Pads) with sonic descriptions.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          genre: { type: Type.STRING },
          lyrics: {
            type: Type.OBJECT,
            properties: {
              verse: { type: Type.STRING },
              chorus: { type: Type.STRING },
              bridge: { type: Type.STRING }
            },
            required: ['verse', 'chorus', 'bridge']
          },
          stems: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, enum: Object.values(StemType) },
                description: { type: Type.STRING },
                intensity: { type: Type.NUMBER }
              },
              required: ['type', 'description', 'intensity']
            }
          }
        },
        required: ['title', 'bpm', 'key', 'genre', 'lyrics', 'stems']
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateVocals = async (text: string, voice: 'Kore' | 'Puck' | 'Zephyr' = 'Kore'): Promise<Uint8Array> => {
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Sing this soulfully and melodically: ${text}` }] }],
    config: {
      responseModalities: ['AUDIO'],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voice },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");

  const binaryString = atob(base64Audio);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

// PCM decoding helper
export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useMemo } from 'react';

interface WaveformProps {
  intensity: number;
  color: string;
  isPlaying: boolean;
  height?: number;
}

const Waveform: React.FC<WaveformProps> = ({ intensity, color, isPlaying, height = 40 }) => {
  const bars = useMemo(() => {
    return Array.from({ length: 60 }).map(() => ({
      baseHeight: Math.random() * intensity * height + 2,
      variance: Math.random() * 5 + 2
    }));
  }, [intensity, height]);

  return (
    <div className="flex items-center gap-[2px] h-full w-full overflow-hidden">
      {bars.map((bar, i) => (
        <div
          key={i}
          className="w-[3px] rounded-full transition-all duration-300"
          style={{
            backgroundColor: color,
            height: isPlaying 
              ? `${bar.baseHeight + (Math.sin(Date.now() / 100 + i) * bar.variance)}px` 
              : `${bar.baseHeight}px`,
            opacity: 0.6 + (intensity * 0.4)
          }}
        />
      ))}
    </div>
  );
};

export default Waveform;

import React from 'react';
import { AudioTrack } from '../types';
import { STEM_CONFIG } from '../constants';

interface MixerTrackProps {
  track: AudioTrack;
  onUpdate: (id: string, updates: Partial<AudioTrack>) => void;
}

const MixerTrack: React.FC<MixerTrackProps> = ({ track, onUpdate }) => {
  const config = STEM_CONFIG[track.type];

  return (
    <div className="flex flex-col items-center bg-zinc-900 rounded-lg p-3 w-24 border border-zinc-800 hover:border-zinc-700 transition-colors">
      <div 
        className="w-10 h-10 rounded-full flex items-center justify-center mb-4 shadow-lg"
        style={{ backgroundColor: `${track.color}20`, color: track.color }}
      >
        {config.icon}
      </div>

      <div className="flex flex-col gap-2 w-full mb-4">
        <button 
          onClick={() => onUpdate(track.id, { isMuted: !track.isMuted })}
          className={`px-2 py-1 rounded text-[10px] font-bold uppercase transition-colors ${track.isMuted ? 'bg-red-500/20 text-red-500' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
        >
          Mute
        </button>
        <button 
          onClick={() => onUpdate(track.id, { isSolo: !track.isSolo })}
          className={`px-2 py-1 rounded text-[10px] font-bold uppercase transition-colors ${track.isSolo ? 'bg-yellow-500/20 text-yellow-500' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
        >
          Solo
        </button>
      </div>

      <div className="h-40 w-full flex justify-center py-2 relative group">
        <div className="w-1 bg-zinc-800 rounded-full h-full absolute" />
        <input
          type="range"
          min="0"
          max="1"
          step="0.01"
          value={track.volume}
          onChange={(e) => onUpdate(track.id, { volume: parseFloat(e.target.value) })}
          className="appearance-none bg-transparent w-40 h-1 -rotate-90 origin-center absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 cursor-pointer
          [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-4 [&::-webkit-slider-thumb]:h-4 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-zinc-100"
        />
      </div>

      <span className="mt-4 text-[10px] font-medium text-zinc-500 truncate w-full text-center uppercase tracking-tighter">
        {track.name}
      </span>
    </div>
  );
};

export default MixerTrack;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { 
  Play, 
  Square, 
  Settings2, 
  Plus, 
  Music2, 
  Save, 
  Wand2, 
  Loader2,
  Share2,
  Trash2,
  Volume2,
  Mic2,
  Disc
} from 'lucide-react';
import { generateSongStructure, generateVocals, decodeAudioData } from './services/geminiService';
import { SongStructure, AudioTrack, StemType } from './types';
import { INITIAL_TRACKS, STEM_CONFIG } from './constants';
import Waveform from './components/Waveform';
import MixerTrack from './components/MixerTrack';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [song, setSong] = useState<SongStructure | null>(null);
  const [tracks, setTracks] = useState<AudioTrack[]>(INITIAL_TRACKS);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const audioCtxRef = useRef<AudioContext | null>(null);
  const sourceNodesRef = useRef<Map<string, AudioBufferSourceNode>>(new Map());
  const gainNodesRef = useRef<Map<string, GainNode>>(new Map());

  const initAudio = () => {
    if (!audioCtxRef.current) {
      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  };

  const stopAll = useCallback(() => {
    setIsPlaying(false);
    sourceNodesRef.current.forEach(node => {
      try { node.stop(); } catch(e) {}
    });
    sourceNodesRef.current.clear();
  }, []);

  const handleUpdateTrack = (id: string, updates: Partial<AudioTrack>) => {
    setTracks(prev => {
      const nextTracks = prev.map(t => t.id === id ? { ...t, ...updates } : t);

      // Handle solo logic immediately in audio graph if playing
      const anySolo = nextTracks.some(t => t.isSolo);

      nextTracks.forEach(track => {
        const gain = gainNodesRef.current.get(track.id);
        if (gain) {
          let targetGain = track.volume;
          if (track.isMuted) targetGain = 0;
          if (anySolo && !track.isSolo) targetGain = 0;
          gain.gain.setTargetAtTime(targetGain, audioCtxRef.current?.currentTime || 0, 0.05);
        }
      });

      return nextTracks;
    });
  };

  const playAll = useCallback(async () => {
    initAudio();
    if (!audioCtxRef.current) return;

    if (audioCtxRef.current.state === 'suspended') {
      await audioCtxRef.current.resume();
    }

    stopAll();
    setIsPlaying(true);

    const anySolo = tracks.some(t => t.isSolo);

    tracks.forEach(track => {
      // In this demo, we use placeholder behavior for non-vocal stems if no buffer is loaded
      // but if a buffer exists (like generated vocals), we play it.
      if (track.buffer) {
        const source = audioCtxRef.current!.createBufferSource();
        source.buffer = track.buffer;

        let gainNode = gainNodesRef.current.get(track.id);
        if (!gainNode) {
          gainNode = audioCtxRef.current!.createGain();
          gainNodesRef.current.set(track.id, gainNode);
        }

        let targetGain = track.volume;
        if (track.isMuted) targetGain = 0;
        if (anySolo && !track.isSolo) targetGain = 0;

        gainNode.gain.value = targetGain;
        source.connect(gainNode);
        gainNode.connect(audioCtxRef.current!.destination);

        source.loop = true;
        source.start(0);
        sourceNodesRef.current.set(track.id, source);
      }
    });
  }, [tracks, stopAll]);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;
    initAudio();
    setIsGenerating(true);
    setError(null);
    stopAll();

    try {
      const structure = await generateSongStructure(prompt);
      setSong(structure);

      // Generate Vocal Stem for the chorus
      const vocalBytes = await generateVocals(structure.lyrics.chorus);
      const vocalBuffer = await decodeAudioData(vocalBytes, audioCtxRef.current!);

      const newTracks: AudioTrack[] = structure.stems.map((stem, index) => ({
        id: `stem-${index}-${Date.now()}`,
        name: `${stem.type.charAt(0) + stem.type.slice(1).toLowerCase()}`,
        type: stem.type,
        buffer: stem.type === StemType.VOCALS ? vocalBuffer : undefined,
        volume: 0.7,
        isMuted: false,
        isSolo: false,
        color: STEM_CONFIG[stem.type].color
      }));

      setTracks(newTracks);
    } catch (err: any) {
      console.error(err);
      setError("Failed to generate music. Please try a different prompt.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#050505] text-zinc-100 selection:bg-pink-500/30">
      {/* Header */}
      <header className="h-16 border-b border-zinc-800 flex items-center justify-between px-6 bg-[#0a0a0a]/80 backdrop-blur-md sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-tr from-pink-500 to-violet-600 rounded-xl flex items-center justify-center shadow-lg shadow-pink-500/10">
            <Disc className="text-white animate-spin-slow" size={24} />
          </div>
          <div>
            <h1 className="font-bold text-lg tracking-tight">Aether Studio</h1>
            <p className="text-[10px] text-zinc-500 uppercase tracking-[0.2em] font-medium">AI Music Engine v2.5</p>
          </div>
        </div>

        {song && (
          <div className="flex items-center gap-8 bg-zinc-900/50 px-6 py-2 rounded-full border border-zinc-800/50">
            <div className="flex flex-col items-center">
              <span className="text-[9px] text-zinc-500 uppercase font-bold tracking-widest">BPM</span>
              <span className="mono text-pink-500 font-bold">{song.bpm}</span>
            </div>
            <div className="h-4 w-[1px] bg-zinc-800" />
            <div className="flex flex-col items-center">
              <span className="text-[9px] text-zinc-500 uppercase font-bold tracking-widest">Key</span>
              <span className="mono text-violet-400 font-bold">{song.key}</span>
            </div>
            <div className="h-4 w-[1px] bg-zinc-800" />
            <div className="flex flex-col items-center">
              <span className="text-[9px] text-zinc-500 uppercase font-bold tracking-widest">Genre</span>
              <span className="text-xs font-semibold">{song.genre}</span>
            </div>
          </div>
        )}

        <div className="flex items-center gap-3">
          <button className="p-2 hover:bg-zinc-800 rounded-lg text-zinc-400 transition-colors">
            <Settings2 size={20} />
          </button>
          <button className="p-2 hover:bg-zinc-800 rounded-lg text-zinc-400 transition-colors">
            <Share2 size={20} />
          </button>
          <button className="flex items-center gap-2 bg-zinc-100 text-zinc-950 px-4 py-2 rounded-lg font-bold text-sm hover:bg-white transition-all active:scale-95 shadow-lg">
            <Save size={16} /> Save Project
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Sidebar: Lyrics & Info */}
        <aside className="w-80 border-r border-zinc-800 bg-[#080808] flex flex-col">
          <div className="p-6 overflow-y-auto flex-1 custom-scrollbar">
            {!song ? (
              <div className="h-full flex flex-col items-center justify-center text-center opacity-40">
                <Music2 size={48} className="mb-4" />
                <p className="text-sm">Enter a prompt to start your production</p>
              </div>
            ) : (
              <div className="space-y-8">
                <div>
                  <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-pink-500 mb-4">Project: {song.title}</h2>
                  <div className="space-y-6">
                    <div>
                      <h3 className="text-xs font-bold text-zinc-400 mb-2 uppercase">Verse</h3>
                      <p className="text-sm leading-relaxed text-zinc-300 font-medium italic">"{song.lyrics.verse}"</p>
                    </div>
                    <div>
                      <h3 className="text-xs font-bold text-zinc-400 mb-2 uppercase">Chorus</h3>
                      <p className="text-sm leading-relaxed text-pink-100 font-bold bg-pink-500/5 p-3 rounded-lg border border-pink-500/10">"{song.lyrics.chorus}"</p>
                    </div>
                    <div>
                      <h3 className="text-xs font-bold text-zinc-400 mb-2 uppercase">Bridge</h3>
                      <p className="text-sm leading-relaxed text-zinc-300 font-medium italic">"{song.lyrics.bridge}"</p>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </aside>

        {/* Timeline Area */}
        <div className="flex-1 flex flex-col bg-[#050505]">
          <div className="flex-1 overflow-y-auto p-6 space-y-4">
            <div className="flex items-center justify-between mb-8">
              <div className="flex items-center gap-4">
                <button 
                  onClick={isPlaying ? stopAll : playAll}
                  className={`w-14 h-14 rounded-full flex items-center justify-center transition-all active:scale-90 shadow-2xl ${isPlaying ? 'bg-zinc-100 text-zinc-900' : 'bg-pink-600 text-white hover:bg-pink-500 shadow-pink-600/20'}`}
                >
                  {isPlaying ? <Square size={24} fill="currentColor" /> : <Play size={24} fill="currentColor" className="ml-1" />}
                </button>
                <div className="flex flex-col">
                  <span className="text-[10px] uppercase font-bold tracking-widest text-zinc-500">Master Engine</span>
                  <span className={`text-lg font-bold mono ${isPlaying ? 'text-pink-500' : 'text-zinc-700'}`}>
                    {isPlaying ? 'RUNNING' : 'STOPPED'}
                  </span>
                </div>
              </div>

              <div className="w-96 flex bg-zinc-900/50 rounded-xl p-1 border border-zinc-800">
                <input 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Atmospheric Cyberpunk beat with melodic female vocals..."
                  className="bg-transparent border-none outline-none px-4 flex-1 text-sm text-zinc-200 placeholder:text-zinc-600"
                  onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
                />
                <button 
                  disabled={isGenerating || !prompt}
                  onClick={handleGenerate}
                  className="bg-pink-600 hover:bg-pink-500 disabled:opacity-50 disabled:cursor-not-allowed text-white p-2 px-4 rounded-lg flex items-center gap-2 transition-all active:scale-95 font-bold text-xs"
                >
                  {isGenerating ? <Loader2 className="animate-spin" size={16} /> : <Wand2 size={16} />}
                  Compose
                </button>
              </div>
            </div>

            {error && (
              <div className="bg-red-500/10 border border-red-500/20 text-red-500 p-4 rounded-xl text-sm flex items-center gap-3 mb-6">
                <Trash2 size={18} />
                {error}
              </div>
            )}

            <div className="space-y-3">
              {tracks.map((track) => (
                <div key={track.id} className="group flex items-center gap-4 bg-zinc-900/30 p-2 pr-6 rounded-xl border border-zinc-800/50 hover:bg-zinc-900/50 transition-all">
                  <div className="w-32 flex flex-col">
                    <div className="flex items-center gap-2 mb-1">
                      <div className="w-2 h-2 rounded-full" style={{ backgroundColor: track.color }} />
                      <span className="text-[10px] font-bold uppercase tracking-wider text-zinc-400 truncate">{track.name}</span>
                    </div>
                    <div className="flex gap-1">
                      <button 
                        onClick={() => handleUpdateTrack(track.id, { isMuted: !track.isMuted })}
                        className={`text-[9px] px-1.5 py-0.5 rounded border transition-all ${track.isMuted ? 'bg-red-500 border-red-400 text-white' : 'border-zinc-700 text-zinc-500 hover:text-zinc-300'}`}
                      >
                        M
                      </button>
                      <button 
                        onClick={() => handleUpdateTrack(track.id, { isSolo: !track.isSolo })}
                        className={`text-[9px] px-1.5 py-0.5 rounded border transition-all ${track.isSolo ? 'bg-yellow-500 border-yellow-400 text-zinc-900 font-bold' : 'border-zinc-700 text-zinc-500 hover:text-zinc-300'}`}
                      >
                        S
                      </button>
                    </div>
                  </div>
                  <div className="flex-1 h-14 bg-[#0a0a0a] rounded-lg border border-zinc-800/30 overflow-hidden relative group-hover:border-zinc-700/50 transition-colors">
                    <Waveform 
                      color={track.color} 
                      intensity={track.buffer ? 0.8 : 0.4} 
                      isPlaying={isPlaying && !track.isMuted} 
                      height={56}
                    />
                    {!track.buffer && (
                      <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-[1px]">
                        <span className="text-[9px] font-bold uppercase tracking-[0.2em] text-zinc-500">Virtual Stem Active</span>
                      </div>
                    )}
                  </div>
                </div>
              ))}

              {isGenerating && (
                <div className="flex flex-col items-center justify-center h-48 border-2 border-dashed border-zinc-800 rounded-2xl bg-zinc-900/20">
                  <Loader2 size={32} className="text-pink-500 animate-spin mb-4" />
                  <p className="text-sm font-medium text-zinc-400 animate-pulse">Orchestrating AI stems and synthesizing vocals...</p>
                </div>
              )}
            </div>
          </div>

          {/* Mixer Area */}
          <div className="h-80 border-t border-zinc-800 bg-[#0a0a0a] p-6 flex gap-4 overflow-x-auto custom-scrollbar">
            {tracks.map(track => (
              <MixerTrack 
                key={track.id} 
                track={track} 
                onUpdate={handleUpdateTrack} 
              />
            ))}

            {/* Master Track */}
            <div className="flex flex-col items-center bg-zinc-900/30 rounded-lg p-3 w-24 border-2 border-zinc-800/80 ml-auto">
              <div className="w-10 h-10 rounded-full flex items-center justify-center mb-4 bg-zinc-100 text-zinc-950 shadow-lg">
                <Volume2 size={18} />
              </div>
              <div className="h-40 w-full flex justify-center py-2 relative group mt-auto">
                <div className="w-1 bg-zinc-800 rounded-full h-full absolute" />
                <div className="absolute bottom-0 w-2 h-1/2 bg-gradient-to-t from-pink-500 to-violet-500 rounded-full blur-[2px] opacity-20" />
                <input
                  type="range"
                  min="0"
                  max="1"
                  step="0.01"
                  defaultValue="0.8"
                  className="appearance-none bg-transparent w-40 h-1 -rotate-90 origin-center absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 cursor-pointer
                  [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-4 [&::-webkit-slider-thumb]:h-4 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white"
                />
