        buffer: stem.type === StemType.VOCALS ? vocalBuffer : undefined,
        volume: 0.7,
        isMuted: false,
        isSolo: false,
        color: STEM_CONFIG[stem.type].color
      }));

      setActiveSong(structure);
      setTracks(newTracks);
      setLibrary(prev => [structure, ...prev]);
    } catch (err: any) {
      console.error(err);
      setError("Failed to generate music. Check your API key or parameters.");
    } finally {
      setIsGenerating(false);
    }
  };

