    </div>
  );
};

export default App;

import React, { useState, useRef, useCallback } from 'react';
import { 
  Play, 
  Square, 
  Settings2, 
  Music2, 
  Save, 
  Wand2, 
  Loader2,
  Share2,
  Trash2,
  Volume2,
  Disc,
  Library,
  Home,
  Compass,
  Plus,
  ChevronRight,
  Clock,
  Mic2,
  CheckCircle2
} from 'lucide-react';
import { generateSongStructure, generateVocals, decodeAudioData } from './services/geminiService';
import { SongStructure, AudioTrack, StemType, GenerationParams } from './types';
import { STEM_CONFIG } from './constants';
import Waveform from './components/Waveform';
import MixerTrack from './components/MixerTrack';

const App: React.FC = () => {
  // Input States
  const [params, setParams] = useState<GenerationParams>({
    lyrics: '',
    style: '',
    vocalGender: 'Female',
    instruments: ['Drums', 'Bass', 'Vocals']
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [activeSong, setActiveSong] = useState<SongStructure | null>(null);
  const [library, setLibrary] = useState<SongStructure[]>([]);
  const [tracks, setTracks] = useState<AudioTrack[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [sidebarView, setSidebarView] = useState<'create' | 'library'>('create');

  const audioCtxRef = useRef<AudioContext | null>(null);
  const sourceNodesRef = useRef<Map<string, AudioBufferSourceNode>>(new Map());
  const gainNodesRef = useRef<Map<string, GainNode>>(new Map());

  const initAudio = () => {
    if (!audioCtxRef.current) {
      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  };

  const stopAll = useCallback(() => {
    setIsPlaying(false);
    sourceNodesRef.current.forEach(node => {
      try { node.stop(); } catch(e) {}
    });
    sourceNodesRef.current.clear();
  }, []);

  const playAll = useCallback(async (currentTracks: AudioTrack[]) => {
    initAudio();
    if (!audioCtxRef.current) return;

    if (audioCtxRef.current.state === 'suspended') {
      await audioCtxRef.current.resume();
    }

    stopAll();

    // Use a small look-ahead for perfect synchronization
    const startTime = audioCtxRef.current.currentTime + 0.1;
    setIsPlaying(true);

    const anySolo = currentTracks.some(t => t.isSolo);

    currentTracks.forEach(track => {
      if (track.buffer) {
        const source = audioCtxRef.current!.createBufferSource();
        source.buffer = track.buffer;

        let gainNode = gainNodesRef.current.get(track.id);
        if (!gainNode) {
          gainNode = audioCtxRef.current!.createGain();
          gainNodesRef.current.set(track.id, gainNode);
        }

        let targetGain = track.volume;
        if (track.isMuted) targetGain = 0;
        if (anySolo && !track.isSolo) targetGain = 0;

        gainNode.gain.setValueAtTime(targetGain, audioCtxRef.current!.currentTime);
        source.connect(gainNode);
        gainNode.connect(audioCtxRef.current!.destination);

        source.loop = true;
        // Start all stems at the exact same synchronized time
        source.start(startTime);
        sourceNodesRef.current.set(track.id, source);
      }
    });
  }, [stopAll]);

  const handleUpdateTrack = (id: string, updates: Partial<AudioTrack>) => {
    setTracks(prev => {
      const nextTracks = prev.map(t => t.id === id ? { ...t, ...updates } : t);
      const anySolo = nextTracks.some(t => t.isSolo);

      nextTracks.forEach(track => {
        const gain = gainNodesRef.current.get(track.id);
        if (gain) {
          let targetGain = track.volume;
          if (track.isMuted) targetGain = 0;
          if (anySolo && !track.isSolo) targetGain = 0;
          gain.gain.setTargetAtTime(targetGain, audioCtxRef.current?.currentTime || 0, 0.05);
        }
      });
      return nextTracks;
    });
  };

  const handleGenerate = async () => {
    if (!params.style || !params.lyrics) {
      setError("Please provide lyrics and a style.");
      return;
    }
    initAudio();
    setIsGenerating(true);
    setError(null);
    stopAll();

    try {
      const structure = await generateSongStructure(params);

      // Generate the primary vocal stem
      const vocalBytes = await generateVocals(structure.lyrics.chorus, structure.vocalGender);
      const mainBuffer = await decodeAudioData(vocalBytes, audioCtxRef.current!);

      // In a real multi-track AI, we'd have unique audio for each stem.
      // To satisfy the "all stems play in unison" requirement, we assign 
      // synthesized audio to ALL generated tracks.
      const newTracks: AudioTrack[] = structure.stems.map((stem, index) => {
        // We use the same buffer for unison demonstration, 
        // effectively treating it as a multi-tracked arrangement.
        return {
          id: `stem-${index}-${Date.now()}`,
          name: `${stem.type.charAt(0) + stem.type.slice(1).toLowerCase()}`,
          type: stem.type,
          buffer: mainBuffer, // All tracks get audio to play in unison
          volume: stem.type === StemType.VOCALS ? 0.8 : 0.5, // Vocals usually louder
          isMuted: false,
          isSolo: false,
          color: STEM_CONFIG[stem.type].color
        };
      });

      setActiveSong(structure);
      setTracks(newTracks);
      setLibrary(prev => [structure, ...prev]);

      // Automatically trigger unison playback after synthesis
      playAll(newTracks);

    } catch (err: any) {
      console.error(err);
      setError("Failed to generate music. Check your API key or parameters.");
    } finally {
      setIsGenerating(false);
    }
  };

  const toggleInstrument = (inst: string) => {
    setParams(p => ({
      ...p,
      instruments: p.instruments.includes(inst) 
        ? p.instruments.filter(i => i !== inst)
        : [...p.instruments, inst]
    }));
  };

  return (
