        <div className="w-12 h-12 bg-pink-600 rounded-2xl flex items-center justify-center shadow-lg shadow-pink-600/20">
          <Disc className="text-white animate-spin-slow" />
        </div>
        <div className="flex flex-col gap-6">
          <button onClick={() => setSidebarView('create')} className={`p-3 rounded-xl transition-all ${sidebarView === 'create' ? 'bg-zinc-800 text-white' : 'text-zinc-600 hover:text-zinc-300'}`}>
            <Home size={24} />
          </button>
          <button onClick={() => setSidebarView('library')} className={`p-3 rounded-xl transition-all ${sidebarView === 'library' ? 'bg-zinc-800 text-white' : 'text-zinc-600 hover:text-zinc-300'}`}>
            <Library size={24} />
          </button>
          <button className="p-3 text-zinc-600 hover:text-zinc-300 transition-all">
            <Compass size={24} />
          </button>
        </div>
        <div className="mt-auto flex flex-col gap-6">
          <button className="p-3 text-zinc-600 hover:text-zinc-300">
            <Settings2 size={24} />
          </button>
          <div className="w-10 h-10 rounded-full bg-zinc-800 border border-zinc-700" />
        </div>
      </nav>

      {/* Control Panel (Side) */}
      <aside className="w-[400px] border-r border-zinc-900 bg-zinc-950/50 flex flex-col overflow-y-auto custom-scrollbar">
        {sidebarView === 'create' ? (
          <div className="p-8 space-y-8">
            <div className="space-y-2">
              <h2 className="text-2xl font-bold tracking-tight">Create</h2>
              <p className="text-zinc-500 text-sm">Generate professional stems in seconds.</p>
            </div>

            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Lyrics / Prompt</label>
                <textarea 
                  value={params.lyrics}
                  onChange={(e) => setParams({...params, lyrics: e.target.value})}
                  placeholder="Enter your own lyrics or a story to generate them..."
                  className="w-full h-32 bg-zinc-900/50 border border-zinc-800 rounded-xl p-4 text-sm focus:ring-2 focus:ring-pink-500/50 focus:border-pink-500 transition-all outline-none resize-none"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Style</label>
                <input 
                  value={params.style}
                  onChange={(e) => setParams({...params, style: e.target.value})}
                  placeholder="e.g. 80s Synthwave, Dark Techno, Jazz Fusion"
                  className="w-full bg-zinc-900/50 border border-zinc-800 rounded-xl p-4 text-sm focus:ring-2 focus:ring-pink-500/50 focus:border-pink-500 transition-all outline-none"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Vocal Preference</label>
                <div className="grid grid-cols-3 gap-2">
                  {['Female', 'Male', 'Non-binary'].map(g => (
                    <button 
                      key={g}
                      onClick={() => setParams({...params, vocalGender: g})}
                      className={`py-2 px-3 rounded-lg border text-xs font-bold transition-all ${params.vocalGender === g ? 'bg-pink-600 border-pink-500 text-white' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
                    >
                      {g}
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Instruments</label>
                <div className="flex flex-wrap gap-2">
                  {['Drums', 'Bass', 'Vocals', 'Guitar', 'Piano', 'Synths', 'Strings'].map(inst => (
                    <button 
                      key={inst}
                      onClick={() => toggleInstrument(inst)}
                      className={`py-1.5 px-3 rounded-full border text-[10px] font-bold uppercase tracking-tighter transition-all ${params.instruments.includes(inst) ? 'bg-zinc-100 text-zinc-950 border-white' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}
                    >
                      {inst}
                    </button>
                  ))}
                </div>
              </div>

              <button 
                onClick={handleGenerate}
                disabled={isGenerating}
                className="w-full bg-zinc-100 text-zinc-950 py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-white active:scale-[0.98] transition-all flex items-center justify-center gap-3 mt-6 shadow-xl disabled:opacity-50"
              >
                {isGenerating ? <Loader2 className="animate-spin" size={20} /> : <Wand2 size={20} />}
                {isGenerating ? 'Synthesizing...' : 'Create Stems'}
              </button>
            </div>
          </div>
        ) : (
          <div className="p-8 space-y-6">
            <h2 className="text-2xl font-bold tracking-tight">Library</h2>
            {library.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-zinc-600">
