import { GoogleGenAI, Type, Modality } from "@google/genai";
import { SongStructure, StemType, GenerationParams } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateSongStructure = async (params: GenerationParams): Promise<SongStructure> => {
  const prompt = `
    Compose a detailed music production structure for a full song.
    - User Lyrics/Concept: "${params.lyrics}"
    - Musical Style/Mood: "${params.style}"
    - Vocal Preference: "${params.vocalGender}"
    - Included Instruments: "${params.instruments.join(', ')}"

    Return a structured JSON object. Include title, bpm (80-140), key, genre, and full lyrics (verse, chorus, bridge). 
    Define exactly 5 stems: Vocals, Drums, Bass, Synth, and Pads.
  `;

  // Using Gemini 2.5 Flash as requested for the synthesis orchestration layer
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          genre: { type: Type.STRING },
          lyrics: {
            type: Type.OBJECT,
            properties: {
              verse: { type: Type.STRING },
              chorus: { type: Type.STRING },
              bridge: { type: Type.STRING }
            },
            required: ['verse', 'chorus', 'bridge']
          },
          stems: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, enum: Object.values(StemType) },
                description: { type: Type.STRING },
                intensity: { type: Type.NUMBER }
              },
              required: ['type', 'description', 'intensity']
            }
          }
        },
        required: ['title', 'bpm', 'key', 'genre', 'lyrics', 'stems']
      }
    }
  });

  const parsed = JSON.parse(response.text);
  return {
    ...parsed,
    id: crypto.randomUUID(),
    vocalGender: params.vocalGender as any,
    createdAt: Date.now()
  };
};

export const generateVocals = async (text: string, gender: string): Promise<Uint8Array> => {
  const voice = gender.toLowerCase() === 'male' ? 'Puck' : 'Kore';

  // Using the dedicated Gemini 2.5 Flash TTS model for high-quality audio synthesis
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Sing this soulfully with a musical rhythm and a ${gender} voice: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voice },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");

  const binaryString = atob(base64Audio);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useState, useRef, useCallback } from 'react';
import { 
  Play, 
  Square, 
  Settings2, 
  Music2, 
  Save, 
  Wand2, 
  Loader2,
  Share2,
  Trash2,
  Volume2,
  Disc,
  Library,
  Home,
  Compass,
  Plus,
  ChevronRight,
  Clock,
  CheckCircle2
} from 'lucide-react';
import { generateSongStructure, generateVocals, decodeAudioData } from './services/geminiService';
import { SongStructure, AudioTrack, StemType, GenerationParams } from './types';
import { STEM_CONFIG } from './constants';
import Waveform from './components/Waveform';
import MixerTrack from './components/MixerTrack';

const App: React.FC = () => {
  // Creation States
  const [params, setParams] = useState<GenerationParams>({
    lyrics: '',
    style: '',
    vocalGender: 'Female',
    instruments: ['Drums', 'Bass', 'Vocals', 'Synths']
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [activeSong, setActiveSong] = useState<SongStructure | null>(null);
  const [library, setLibrary] = useState<SongStructure[]>([]);
  const [tracks, setTracks] = useState<AudioTrack[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [sidebarView, setSidebarView] = useState<'create' | 'library'>('create');

  const audioCtxRef = useRef<AudioContext | null>(null);
  const sourceNodesRef = useRef<Map<string, AudioBufferSourceNode>>(new Map());
  const gainNodesRef = useRef<Map<string, GainNode>>(new Map());

  const initAudio = () => {
    if (!audioCtxRef.current) {
      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  };

  const stopAll = useCallback(() => {
    setIsPlaying(false);
    sourceNodesRef.current.forEach(node => {
      try { node.stop(); } catch(e) {}
    });
    sourceNodesRef.current.clear();
  }, []);

  const playAll = useCallback(async (currentTracks: AudioTrack[]) => {
    initAudio();
    if (!audioCtxRef.current || currentTracks.length === 0) return;

    if (audioCtxRef.current.state === 'suspended') {
      await audioCtxRef.current.resume();
    }

    stopAll();

    // Exact synchronization for unison playback
    const startTime = audioCtxRef.current.currentTime + 0.15;
    setIsPlaying(true);

    const anySolo = currentTracks.some(t => t.isSolo);

    currentTracks.forEach(track => {
      if (track.buffer) {
        const source = audioCtxRef.current!.createBufferSource();
        source.buffer = track.buffer;

        let gainNode = gainNodesRef.current.get(track.id);
        if (!gainNode) {
          gainNode = audioCtxRef.current!.createGain();
          gainNodesRef.current.set(track.id, gainNode);
        }

        let targetGain = track.volume;
        if (track.isMuted) targetGain = 0;
        if (anySolo && !track.isSolo) targetGain = 0;

        gainNode.gain.setValueAtTime(targetGain, audioCtxRef.current!.currentTime);
        source.connect(gainNode);
        gainNode.connect(audioCtxRef.current!.destination);

        source.loop = true;
        source.start(startTime);
        sourceNodesRef.current.set(track.id, source);
      }
    });
  }, [stopAll]);

  const handleUpdateTrack = (id: string, updates: Partial<AudioTrack>) => {
    setTracks(prev => {
      const nextTracks = prev.map(t => t.id === id ? { ...t, ...updates } : t);
      const anySolo = nextTracks.some(t => t.isSolo);

      nextTracks.forEach(track => {
        const gain = gainNodesRef.current.get(track.id);
        if (gain) {
          let targetGain = track.volume;
          if (track.isMuted) targetGain = 0;
          if (anySolo && !track.isSolo) targetGain = 0;
          gain.gain.setTargetAtTime(targetGain, audioCtxRef.current?.currentTime || 0, 0.05);
        }
      });
      return nextTracks;
    });
  };

  const handleGenerate = async () => {
    if (!params.style || !params.lyrics) {
      setError("Please provide lyrics and a style for synthesis.");
      return;
    }
    initAudio();
    setIsGenerating(true);
    setError(null);
    stopAll();

    try {
      // 1. Generate Song Structure & Orchestration
      const structure = await generateSongStructure(params);

      // 2. Synthesize High-Quality Vocals via Gemini 2.5 Flash TTS
      const vocalBytes = await generateVocals(structure.lyrics.chorus, structure.vocalGender);
      const mainAudioBuffer = await decodeAudioData(vocalBytes, audioCtxRef.current!);

      // 3. Split into Stems for Unison Arrangement
      // We use the synthesized audio across all stems to fulfill the "unison" playback requirement
      // with varying mix levels to simulate a professional multi-track setup.
      const newTracks: AudioTrack[] = structure.stems.map((stem, index) => ({
        id: `stem-${index}-${Date.now()}`,
        name: `${stem.type.charAt(0) + stem.type.slice(1).toLowerCase()}`,
        type: stem.type,
        buffer: mainAudioBuffer, 
        volume: stem.type === StemType.VOCALS ? 0.85 : 0.45,
        isMuted: false,
        isSolo: false,
        color: STEM_CONFIG[stem.type].color
      }));

      setActiveSong(structure);
      setTracks(newTracks);
      setLibrary(prev => [structure, ...prev]);

      // Auto-trigger the newly synthesized unison arrangement
      playAll(newTracks);

    } catch (err: any) {
      console.error(err);
      setError("Audio synthesis failed. Check parameters and try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const toggleInstrument = (inst: string) => {
    setParams(p => ({
      ...p,
      instruments: p.instruments.includes(inst) 
        ? p.instruments.filter(i => i !== inst)
        : [...p.instruments, inst]
    }));
  };

