import { GoogleGenAI, Type, Modality } from "@google/genai";
import { SongStructure, StemType, GenerationParams } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateSongStructure = async (params: GenerationParams): Promise<SongStructure> => {
  const prompt = `
    You are a world-class Music Producer. Compose a professional song structure.
    - User Concept: "${params.lyrics}"
    - Style: "${params.style}"
    - Vocal Gender: "${params.vocalGender}"
    - Instruments: "${params.instruments.join(', ')}"

    CRITICAL REALISM REQUIREMENTS:
    1. The lyrics must include emotional cues like (breathe), [beat drop], or ~vibrato~.
    2. Suggest a BPM that feels natural for the genre.
    3. Stems must include: Vocals, Drums, Bass, Synth, and Pads.

    Return a valid JSON object with: title, bpm, key, genre, lyrics (verse, chorus, bridge), and stems array.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          genre: { type: Type.STRING },
          lyrics: {
            type: Type.OBJECT,
            properties: {
              verse: { type: Type.STRING },
              chorus: { type: Type.STRING },
              bridge: { type: Type.STRING }
            },
            required: ['verse', 'chorus', 'bridge']
          },
          stems: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, enum: Object.values(StemType) },
                description: { type: Type.STRING },
                intensity: { type: Type.NUMBER }
              },
              required: ['type', 'description', 'intensity']
            }
          }
        },
        required: ['title', 'bpm', 'key', 'genre', 'lyrics', 'stems']
      }
    }
  });

  const parsed = JSON.parse(response.text);
  return {
    ...parsed,
    id: crypto.randomUUID(),
    vocalGender: params.vocalGender as any,
    createdAt: Date.now()
  };
};

export const generateVocals = async (text: string, gender: string): Promise<Uint8Array> => {
  const voice = gender.toLowerCase() === 'male' ? 'Puck' : 'Kore';

  // Specific musical synthesis prompt for realistic singing phrasing
  const vocalPrompt = `
    Sing this lyric with a natural, human performance. 
    Include subtle breaths, emotional phrasing, and a realistic melody that fits a "${gender}" voice.
    LYRICS: ${text}
  `;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: vocalPrompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voice },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");

  const binaryString = atob(base64Audio);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

