import React, { useEffect, useState } from 'react';
import { AudioTrack } from '../types';
import { STEM_CONFIG } from '../constants';

interface MixerTrackProps {
  track: AudioTrack;
  onUpdate: (id: string, updates: Partial<AudioTrack>) => void;
  isPlaying?: boolean;
}

const MixerTrack: React.FC<MixerTrackProps> = ({ track, onUpdate, isPlaying }) => {
  const config = STEM_CONFIG[track.type];
  const [meterLevel, setMeterLevel] = useState(0);

  // Simulated VU Meter behavior for visual realism
  useEffect(() => {
    let interval: number;
    if (isPlaying && !track.isMuted) {
      interval = window.setInterval(() => {
        // Random bounce around the current volume setting
        const base = track.volume * 70;
        const bounce = Math.random() * 20;
        setMeterLevel(Math.min(100, base + bounce));
      }, 80);
    } else {
      setMeterLevel(0);
    }
    return () => clearInterval(interval);
  }, [isPlaying, track.isMuted, track.volume]);

  const getPanLabel = (val: number) => {
    if (Math.abs(val) < 0.1) return 'C';
    return val < 0 ? `${Math.abs(Math.round(val * 100))}L` : `${Math.round(val * 100)}R`;
  };

  return (
    <div className="flex flex-col items-center bg-zinc-900/60 rounded-3xl p-5 w-32 border border-zinc-800/50 hover:border-zinc-700/50 transition-all shadow-2xl relative overflow-hidden group">
      {/* Track Label Tag */}
      <div 
        className="absolute top-0 left-0 right-0 h-1" 
        style={{ backgroundColor: track.color }} 
      />

      {/* Icon & Name */}
      <div className="flex flex-col items-center gap-2 mb-6 mt-2">
        <div 
          className="w-10 h-10 rounded-2xl flex items-center justify-center shadow-lg border border-white/5 transition-transform group-hover:scale-110"
          style={{ backgroundColor: `${track.color}15`, color: track.color, boxShadow: `0 0 20px ${track.color}10` }}
        >
          {config.icon}
        </div>
        <span className="text-[10px] font-black text-zinc-400 truncate w-full text-center uppercase tracking-widest">
          {track.name}
        </span>
      </div>

      {/* Solo/Mute Controls */}
      <div className="grid grid-cols-2 gap-1.5 w-full mb-6">
        <button 
          onClick={() => onUpdate(track.id, { isMuted: !track.isMuted })}
          className={`py-2 rounded-lg text-[8px] font-black uppercase tracking-widest transition-all border ${
            track.isMuted 
              ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-900/20' 
              : 'bg-zinc-800 border-zinc-700 text-zinc-500 hover:text-zinc-300 hover:bg-zinc-750'
          }`}
        >
          Mute
        </button>
        <button 
          onClick={() => onUpdate(track.id, { isSolo: !track.isSolo })}
          className={`py-2 rounded-lg text-[8px] font-black uppercase tracking-widest transition-all border ${
            track.isSolo 
              ? 'bg-yellow-500 border-yellow-400 text-zinc-900 shadow-lg shadow-yellow-900/20' 
              : 'bg-zinc-800 border-zinc-700 text-zinc-500 hover:text-zinc-300 hover:bg-zinc-750'
          }`}
        >
          Solo
        </button>
      </div>

      {/* Panning Control */}
      <div className="w-full mb-8 flex flex-col items-center gap-1.5">
        <div className="flex justify-between w-full px-1">
          <span className="text-[7px] font-black text-zinc-600">L</span>
          <span className="text-[8px] font-black text-pink-500/80 tracking-tighter mono">{getPanLabel(track.pan)}</span>
          <span className="text-[7px] font-black text-zinc-600">R</span>
        </div>
        <div className="relative w-full h-1.5 bg-zinc-800/80 rounded-full border border-zinc-700/30">
          <div 
            className="absolute top-1/2 -translate-y-1/2 h-full bg-zinc-600/30 rounded-full"
            style={{ 
              left: track.pan < 0 ? `${(track.pan + 1) * 50}%` : '50%',
              right: track.pan > 0 ? `${100 - (track.pan + 1) * 50}%` : '50%'
            }}
          />
          <input 
            type="range"
            min="-1"
            max="1"
            step="0.01"
            value={track.pan}
            onChange={(e) => onUpdate(track.id, { pan: parseFloat(e.target.value) })}
            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
          />
          <div 
            className="absolute top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full border border-zinc-400 shadow-md pointer-events-none transition-transform active:scale-125"
            style={{ left: `calc(${(track.pan + 1) * 50}% - 6px)` }}
          />
        </div>
      </div>

      {/* Volume Section with VU Meter */}
      <div className="flex gap-4 h-48 w-full items-center justify-center">
        {/* VU Meter */}
        <div className="w-2.5 h-full bg-black/40 rounded-full border border-zinc-800/50 relative overflow-hidden flex flex-col justify-end p-[1px]">
          <div 
            className="w-full transition-all duration-75 rounded-full"
            style={{ 
              height: `${meterLevel}%`,
              background: meterLevel > 85 
                ? 'linear-gradient(to top, #10b981, #f59e0b, #ef4444)' 
                : meterLevel > 60 
                  ? 'linear-gradient(to top, #10b981, #f59e0b)' 
                  : '#10b981',
              boxShadow: `0 0 10px ${meterLevel > 85 ? '#ef444450' : '#10b98130'}`
            }}
          />
          {/* DB markings */}
          <div className="absolute inset-0 flex flex-col justify-between py-2 pointer-events-none opacity-20">
            {[0, 1, 2, 3, 4, 5].map(i => <div key={i} className="w-full h-[1px] bg-white" />)}
          </div>
        </div>

        {/* Fader */}
        <div className="relative h-full w-8 flex flex-col items-center">
          <div className="absolute inset-y-0 w-1 bg-zinc-800 rounded-full shadow-inner" />

          {/* Level Numbers */}
          <div className="absolute -left-5 inset-y-0 flex flex-col justify-between text-[6px] font-bold text-zinc-600 py-1 pointer-events-none">
            <span>+6</span><span>0</span><span>-6</span><span>-12</span><span>-24</span><span>-&infin;</span>
          </div>

          <input
            type="range"
            min="0"
            max="1.2"
            step="0.001"
            value={track.volume}
            onChange={(e) => onUpdate(track.id, { volume: parseFloat(e.target.value) })}
            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-20 -rotate-180 fader-vertical"
            style={{ direction: 'rtl' }}
          />

          {/* Visual Fader Cap */}
          <div 
            className="absolute w-7 h-10 bg-zinc-300 rounded-md border-y border-zinc-400 shadow-[0_4px_8px_rgba(0,0,0,0.5),inset_0_1px_0_rgba(255,255,255,0.4)] flex flex-col items-center justify-center pointer-events-none transition-all"
            style={{ 
              bottom: `calc(${Math.min(100, (track.volume / 1.2) * 100)}% - 20px)`,
              borderColor: track.volume > 1.0 ? track.color : 'inherit'
            }}
          >
            <div className="w-full h-[2px] bg-zinc-800/20 mb-[2px]" />
            <div className="w-full h-1 bg-white/20 mb-[2px]" />
            <div className="w-full h-[2px] bg-zinc-800/20" />

            {/* Center Line with Glow */}
            <div 
              className="absolute left-0 right-0 h-[2px] shadow-[0_0_8px_currentColor]" 
              style={{ color: track.color, backgroundColor: 'currentColor' }} 
            />
          </div>
        </div>
      </div>

      <style>{`
        .fader-vertical {
          writing-mode: bt-lr; /* Bottom to top */
          appearance: slider-vertical;
        }
      `}</style>
    </div>
  );
};

export default MixerTrack;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { 
  Play, 
  Square, 
  Settings2, 
  Music2, 
  Save, 
  Wand2, 
  Loader2,
  Share2,
  Trash2,
  Volume2,
  Disc,
  Library,
  Home,
  Compass,
  Plus,
  ChevronRight,
  Clock,
  CheckCircle2,
  Sparkles
} from 'lucide-react';
import { generateSongStructure, generateVocals, decodeAudioData } from './services/geminiService';
import { SongStructure, AudioTrack, StemType, GenerationParams } from './types';
import { STEM_CONFIG } from './constants';
import Waveform from './components/Waveform';
import MixerTrack from './components/MixerTrack';

const App: React.FC = () => {
  const [params, setParams] = useState<GenerationParams>({
    lyrics: '',
    style: '',
    vocalGender: 'Female',
    instruments: ['Drums', 'Bass', 'Vocals', 'Synths']
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [activeSong, setActiveSong] = useState<SongStructure | null>(null);
  const [library, setLibrary] = useState<SongStructure[]>([]);
  const [tracks, setTracks] = useState<AudioTrack[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [sidebarView, setSidebarView] = useState<'create' | 'library'>('create');

  const audioCtxRef = useRef<AudioContext | null>(null);
  const sourceNodesRef = useRef<Map<string, AudioBufferSourceNode>>(new Map());
  const gainNodesRef = useRef<Map<string, GainNode>>(new Map());
  const panNodesRef = useRef<Map<string, PannerNode>>(new Map());
  const masterSaturationRef = useRef<WaveShaperNode | null>(null);

  const initAudio = () => {
    if (!audioCtxRef.current) {
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioCtxRef.current = ctx;

      // Master Saturation Curve (Realistic Analog Warmth)
      const shaper = ctx.createWaveShaper();
      const curve = new Float32Array(44100);
      const k = 0.5; // Soft saturation amount
      for (let i = 0; i < 44100; i++) {
        const x = (i * 2) / 44100 - 1;
        curve[i] = ((1 + k) * x) / (1 + k * Math.abs(x));
      }
      shaper.curve = curve;
      shaper.oversample = '4x';
      shaper.connect(ctx.destination);
      masterSaturationRef.current = shaper;
    }
  };

  const stopAll = useCallback(() => {
    setIsPlaying(false);
    sourceNodesRef.current.forEach(node => {
      try { node.stop(); } catch(e) {}
    });
    sourceNodesRef.current.clear();
  }, []);

  const playAll = useCallback(async (currentTracks: AudioTrack[]) => {
    initAudio();
    if (!audioCtxRef.current || currentTracks.length === 0) return;
    if (audioCtxRef.current.state === 'suspended') await audioCtxRef.current.resume();

    stopAll();
    const ctx = audioCtxRef.current!;
    const globalStartTime = ctx.currentTime + 0.2;
    setIsPlaying(true);

    const anySolo = currentTracks.some(t => t.isSolo);

    currentTracks.forEach(track => {
      if (track.buffer) {
        const source = ctx.createBufferSource();
        source.buffer = track.buffer;

        // 1. Gain Management
        let gainNode = gainNodesRef.current.get(track.id);
        if (!gainNode) {
          gainNode = ctx.createGain();
          gainNodesRef.current.set(track.id, gainNode);
        }

        let targetGain = track.volume;
        if (track.isMuted) targetGain = 0;
        if (anySolo && !track.isSolo) targetGain = 0;
        gainNode.gain.setValueAtTime(targetGain, ctx.currentTime);

        // 2. Spatial Panning
        let panNode = panNodesRef.current.get(track.id);
        if (!panNode) {
          panNode = ctx.createPanner();
          panNode.panningModel = 'equalpower';
          panNodesRef.current.set(track.id, panNode);
        }
        panNode.positionX.setValueAtTime(track.pan, ctx.currentTime);

        // Routing: Source -> Panner -> Gain -> Master Saturation
        source.connect(panNode);
        panNode.connect(gainNode);
        gainNode.connect(masterSaturationRef.current!);

        // 3. HUMANIZER ENGINE: Micro-timing Jitter
        // Real players are +/- 30ms off the grid.
        const jitter = (Math.random() - 0.5) * 0.035; 
        const humanStartTime = globalStartTime + jitter;

        source.loop = true;
        source.start(humanStartTime);
        sourceNodesRef.current.set(track.id, source);
      }
    });
  }, [stopAll]);

  const handleUpdateTrack = (id: string, updates: Partial<AudioTrack>) => {
    setTracks(prev => {
      const nextTracks = prev.map(t => t.id === id ? { ...t, ...updates } : t);
      const anySolo = nextTracks.some(t => t.isSolo);

      nextTracks.forEach(track => {
        const gain = gainNodesRef.current.get(track.id);
        if (gain) {
          let targetGain = track.volume;
          if (track.isMuted) targetGain = 0;
          if (anySolo && !track.isSolo) targetGain = 0;
          gain.gain.setTargetAtTime(targetGain, audioCtxRef.current?.currentTime || 0, 0.05);
        }
        const pan = panNodesRef.current.get(track.id);
        if (pan) {
          pan.positionX.setTargetAtTime(track.pan, audioCtxRef.current?.currentTime || 0, 0.05);
        }
      });
      return nextTracks;
    });
  };

  const handleGenerate = async () => {
    if (!params.style || !params.lyrics) {
      setError("Provide lyrics and style for realistic synthesis.");
      return;
    }
    initAudio();
    setIsGenerating(true);
    setError(null);
    stopAll();

    try {
      const structure = await generateSongStructure(params);
      const vocalBytes = await generateVocals(structure.lyrics.chorus, structure.vocalGender);
      const mainAudioBuffer = await decodeAudioData(vocalBytes, audioCtxRef.current!);

      const newTracks: AudioTrack[] = structure.stems.map((stem, index) => {
        // Preset Spatial Panning for a realistic band stage
        let defaultPan = 0;
        if (stem.type === StemType.SYNTH) defaultPan = -0.6;
        if (stem.type === StemType.PADS) defaultPan = 0.6;
        if (stem.type === StemType.GUITAR) defaultPan = -0.4;
        if (stem.type === StemType.PIANO) defaultPan = 0.4;

        return {
          id: `stem-${index}-${Date.now()}`,
          name: `${stem.type.charAt(0) + stem.type.slice(1).toLowerCase()}`,
          type: stem.type,
          buffer: mainAudioBuffer, 
          volume: stem.type === StemType.VOCALS ? 0.9 : 0.45,
          pan: defaultPan,
          isMuted: false,
          isSolo: false,
          color: STEM_CONFIG[stem.type].color
        };
      });

      setActiveSong(structure);
      setTracks(newTracks);
      setLibrary(prev => [structure, ...prev]);
      playAll(newTracks);
    } catch (err: any) {
      console.error(err);
      setError("Realistic synthesis failed. Verify project parameters.");
    } finally {
      setIsGenerating(false);
    }
  };

  const toggleInstrument = (inst: string) => {
    setParams(p => ({
      ...p,
      instruments: p.instruments.includes(inst) 
        ? p.instruments.filter(i => i !== inst)
        : [...p.instruments, inst]
    }));
  };

  return (
    <div className="flex h-screen bg-[#020202] text-zinc-100 font-sans selection:bg-pink-500/30">
      <nav className="w-16 border-r border-zinc-900 flex flex-col items-center py-6 gap-8 bg-zinc-950/50 backdrop-blur-md">
        <div className="w-10 h-10 bg-gradient-to-tr from-pink-600 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-pink-600/20">
          <Disc className="text-white animate-spin-slow" size={20} />
        </div>
        <div className="flex flex-col gap-6">
          <button onClick={() => setSidebarView('create')} className={`p-2.5 rounded-xl transition-all ${sidebarView === 'create' ? 'bg-zinc-800 text-white shadow-inner' : 'text-zinc-600 hover:text-zinc-300'}`}>
            <Home size={22} />
          </button>
          <button onClick={() => setSidebarView('library')} className={`p-2.5 rounded-xl transition-all ${sidebarView === 'library' ? 'bg-zinc-800 text-white shadow-inner' : 'text-zinc-600 hover:text-zinc-300'}`}>
            <Library size={22} />
          </button>
          <button className="p-2.5 text-zinc-600 hover:text-zinc-300 transition-all">
            <Compass size={22} />
          </button>
        </div>
        <div className="mt-auto flex flex-col gap-6">
