import { STEM_CONFIG } from './constants';
import Waveform from './components/Waveform';
import MixerTrack from './components/MixerTrack';

const App: React.FC = () => {
  const [params, setParams] = useState<GenerationParams>({
    lyrics: '',
    style: '',
    vocalGender: 'Female',
    vocalStyle: 'Emotional',
    instruments: ['Drums', 'Bass', 'Vocals', 'Synths', 'Pads']
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState<string>('');
  const [activeSong, setActiveSong] = useState<SongStructure | null>(null);
  const [library, setLibrary] = useState<SongStructure[]>([]);
  const [tracks, setTracks] = useState<AudioTrack[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [sidebarView, setSidebarView] = useState<'create' | 'library'>('create');

  const audioCtxRef = useRef<AudioContext | null>(null);
  const sourceNodesRef = useRef<Map<string, AudioBufferSourceNode>>(new Map());
  const gainNodesRef = useRef<Map<string, GainNode>>(new Map());
  const panNodesRef = useRef<Map<string, PannerNode>>(new Map());
  const masterCompressorRef = useRef<DynamicsCompressorNode | null>(null);
  const masterSaturationRef = useRef<WaveShaperNode | null>(null);

  const initAudio = () => {
    if (!audioCtxRef.current) {
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioCtxRef.current = ctx;

      // 1. Professional "Glue" Compressor
      const compressor = ctx.createDynamicsCompressor();
      compressor.threshold.setValueAtTime(-24, ctx.currentTime);
      compressor.knee.setValueAtTime(30, ctx.currentTime);
      compressor.ratio.setValueAtTime(12, ctx.currentTime);
      compressor.attack.setValueAtTime(0.003, ctx.currentTime);
      compressor.release.setValueAtTime(0.25, ctx.currentTime);
      masterCompressorRef.current = compressor;

      // 2. Analog Tape Saturation
      const shaper = ctx.createWaveShaper();
      const curve = new Float32Array(44100);
      const k = 0.45;
      for (let i = 0; i < 44100; i++) {
        const x = (i * 2) / 44100 - 1;
        curve[i] = ((1 + k) * x) / (1 + k * Math.abs(x));
      }
      shaper.curve = curve;
      shaper.oversample = '4x';

      // Routing: Compressor -> Saturation -> Output
      compressor.connect(shaper);
      shaper.connect(ctx.destination);
      masterSaturationRef.current = shaper;
    }
  };

  const stopAll = useCallback(() => {
    setIsPlaying(false);
    sourceNodesRef.current.forEach(node => {
      try { node.stop(); } catch(e) {}
    });
    sourceNodesRef.current.clear();
  }, []);

  const playAll = useCallback(async (currentTracks: AudioTrack[]) => {
    initAudio();
    if (!audioCtxRef.current || currentTracks.length === 0) return;
    if (audioCtxRef.current.state === 'suspended') await audioCtxRef.current.resume();

    stopAll();
    const ctx = audioCtxRef.current!;
    const globalStartTime = ctx.currentTime + 0.5;
    setIsPlaying(true);

    const anySolo = currentTracks.some(t => t.isSolo);

    currentTracks.forEach(track => {
      if (track.buffer) {
        const source = ctx.createBufferSource();
        source.buffer = track.buffer;

        let gainNode = gainNodesRef.current.get(track.id);
        if (!gainNode) {
          gainNode = ctx.createGain();
          gainNodesRef.current.set(track.id, gainNode);
        }

        let targetGain = track.volume;
        if (track.isMuted) targetGain = 0;
        if (anySolo && !track.isSolo) targetGain = 0;
        gainNode.gain.setValueAtTime(targetGain, ctx.currentTime);

        let panNode = panNodesRef.current.get(track.id);
        if (!panNode) {
          panNode = ctx.createPanner();
          panNode.panningModel = 'equalpower';
          panNodesRef.current.set(track.id, panNode);
        }
        panNode.positionX.setValueAtTime(track.pan, ctx.currentTime);

        // Routing: Source -> Panner -> Gain -> Master Glue Compressor
        source.connect(panNode);
        panNode.connect(gainNode);
        gainNode.connect(masterCompressorRef.current!);

        // HUMANIZER JITTER: Per-instrument micro-timing offsets
        const jitter = (Math.random() - 0.5) * 0.055; 
        const humanStartTime = globalStartTime + jitter;

        source.loop = true;
        source.start(humanStartTime);
        sourceNodesRef.current.set(track.id, source);
      }
    });
  }, [stopAll]);

  const handleUpdateTrack = (id: string, updates: Partial<AudioTrack>) => {
    setTracks(prev => {
      const nextTracks = prev.map(t => t.id === id ? { ...t, ...updates } : t);
      const anySolo = nextTracks.some(t => t.isSolo);

      nextTracks.forEach(track => {
        const gain = gainNodesRef.current.get(track.id);
        if (gain) {
          let targetGain = track.volume;
          if (track.isMuted) targetGain = 0;
          if (anySolo && !track.isSolo) targetGain = 0;
          gain.gain.setTargetAtTime(targetGain, audioCtxRef.current?.currentTime || 0, 0.05);
        }
        const pan = panNodesRef.current.get(track.id);
        if (pan) {
          pan.positionX.setTargetAtTime(track.pan, audioCtxRef.current?.currentTime || 0, 0.08);
        }
      });
      return nextTracks;
    });
  };

  const handleGenerate = async () => {
    if (!params.style || !params.lyrics) {
      setError("Provide a musical direction and lyrics for the band to perform.");
      return;
    }
    initAudio();
    setIsGenerating(true);
    setError(null);
    stopAll();

    try {
      setGenerationStep('Writing Arrangement...');
      const structure = await generateSongStructure(params);

      const synthesisPromises = structure.stems.map(async (stem, index) => {
        setGenerationStep(`Recording ${stem.type}...`);

        const instruction = stem.type === StemType.VOCALS 
          ? structure.lyrics.chorus 
          : (stem as any).performance_instruction;

        const audioBytes = await synthesizeStemAudio(instruction, stem.type as StemType, {
          genre: structure.genre,
          bpm: structure.bpm,
          key: structure.key,
          vocalStyle: params.vocalStyle
        });

        const buffer = await decodeAudioData(audioBytes, audioCtxRef.current!);

        // Pro Spatial Panning Presets
        let defaultPan = 0;
        if (stem.type === StemType.SYNTH) defaultPan = -0.55;
        if (stem.type === StemType.PADS) defaultPan = 0.55;
        if (stem.type === StemType.GUITAR) defaultPan = -0.3;
        if (stem.type === StemType.PIANO) defaultPan = 0.3;

        return {
          id: `stem-${index}-${Date.now()}`,
          name: `${stem.type}`,
          type: stem.type as StemType,
          buffer: buffer, 
          volume: stem.type === StemType.VOCALS ? 0.95 : stem.type === StemType.DRUMS ? 0.7 : 0.55,
          pan: defaultPan,
          isMuted: false,
          isSolo: false,
          color: STEM_CONFIG[stem.type as StemType].color
        };
      });

      const tracksResult = await Promise.all(synthesisPromises);
      setTracks(tracksResult);
      setActiveSong(structure);
      setLibrary(prev => [structure, ...prev]);
      playAll(tracksResult);

    } catch (err: any) {
      console.error(err);
      setError("Band session failed. Ensure your connection is stable.");
    } finally {
      setIsGenerating(false);
      setGenerationStep('');
    }
  };

  const VOCAL_STYLES = ['Emotional', 'Powerful', 'Soft', 'Raspy', 'Soulful'];

  return (
    <div className="flex h-screen bg-[#020202] text-zinc-100 font-sans selection:bg-pink-500/30">
      <nav className="w-16 border-r border-zinc-900 flex flex-col items-center py-6 gap-8 bg-zinc-950/50 backdrop-blur-md">
        <div className="w-10 h-10 bg-gradient-to-tr from-pink-600 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-pink-600/20">
          <Disc className="text-white animate-spin-slow" size={20} />
        </div>
        <div className="flex flex-col gap-6">
          <button onClick={() => setSidebarView('create')} className={`p-2.5 rounded-xl transition-all ${sidebarView === 'create' ? 'bg-zinc-800 text-white shadow-inner' : 'text-zinc-600 hover:text-zinc-300'}`}>
            <Home size={22} />
          </button>
          <button onClick={() => setSidebarView('library')} className={`p-2.5 rounded-xl transition-all ${sidebarView === 'library' ? 'bg-zinc-800 text-white shadow-inner' : 'text-zinc-600 hover:text-zinc-300'}`}>
            <Library size={22} />
          </button>
        </div>
        <div className="mt-auto flex flex-col gap-6">
          <button className="p-2.5 text-zinc-600 hover:text-zinc-300">
            <Settings2 size={22} />
          </button>
          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-zinc-700 to-zinc-900 border border-zinc-800 shadow-inner" />
        </div>
      </nav>

      <aside className="w-[380px] border-r border-zinc-900 bg-[#050505] flex flex-col overflow-y-auto custom-scrollbar shadow-2xl">
        {sidebarView === 'create' ? (
          <div className="p-7 space-y-8">
            <header>
              <h2 className="text-2xl font-black tracking-tight mb-1">Aether Console</h2>
              <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.2em]">High Performance Music Engine</p>
            </header>

            <div className="space-y-6">
              <div className="space-y-2.5">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Vocal Theme</label>
                <textarea 
                  value={params.lyrics}
                  onChange={(e) => setParams({...params, lyrics: e.target.value})}
                  placeholder="The vocalist will interpret these emotionally..."
                  className="w-full h-32 bg-zinc-900/30 border border-zinc-800/80 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-pink-500/30 focus:border-pink-500/50 transition-all outline-none resize-none placeholder:text-zinc-700"
                />
              </div>

              <div className="space-y-2.5">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Genre Target</label>
                <input 
                  value={params.style}
                  onChange={(e) => setParams({...params, style: e.target.value})}
                  placeholder="Lo-fi Soul, Grungy Rock, Cinematic Pop..."
                  className="w-full bg-zinc-900/30 border border-zinc-800/80 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-pink-500/30 focus:border-pink-500/50 transition-all outline-none"
                />
              </div>

              <div className="space-y-4">
                <div className="space-y-2.5">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Vocal Profile</label>
                  <div className="grid grid-cols-3 gap-2">
                    {['Female', 'Male', 'Non-binary'].map(g => (
                      <button 
                        key={g}
                        onClick={() => setParams({...params, vocalGender: g})}
                        className={`py-3 px-3 rounded-xl border text-[11px] font-black uppercase tracking-widest transition-all ${params.vocalGender === g ? 'bg-pink-600 border-pink-500 text-white' : 'bg-zinc-900/40 border-zinc-800 text-zinc-500'}`}
                      >
                        {g}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-2.5">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Performance Style</label>
                  <div className="flex flex-wrap gap-2">
                    {VOCAL_STYLES.map(s => (
                      <button 
                        key={s}
                        onClick={() => setParams({...params, vocalStyle: s})}
                        className={`py-2 px-4 rounded-full border text-[9px] font-black uppercase tracking-widest transition-all ${params.vocalStyle === s ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-zinc-900/40 border-zinc-800 text-zinc-500 hover:text-zinc-300'}`}
                      >
                        {s}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-2.5">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Active Band Stems</label>
                <div className="flex flex-wrap gap-2">
                  {['Drums', 'Bass', 'Vocals', 'Synths', 'Pads'].map(inst => (
                    <div key={inst} className="bg-zinc-900/40 border border-zinc-800 px-3 py-1.5 rounded-full text-[10px] font-black text-zinc-500 flex items-center gap-2">
                       <div className="w-1.5 h-1.5 rounded-full bg-pink-500 animate-pulse" /> {inst}
                    </div>
                  ))}
                </div>
              </div>

              <button 
                onClick={handleGenerate}
                disabled={isGenerating}
                className="group relative w-full bg-white text-black py-4.5 rounded-2xl font-black uppercase tracking-[0.2em] text-xs hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-3 mt-8 shadow-2xl disabled:opacity-40"
              >
                <Zap size={18} className="text-indigo-600 group-hover:animate-bounce" />
                {isGenerating ? 'Synthesizing...' : 'Generate Full Band'}
              </button>
            </div>
          </div>
        ) : (
          <div className="p-7 space-y-6">
            <h2 className="text-2xl font-black tracking-tight">Project History</h2>
            {library.length === 0 ? (
              <p className="text-zinc-600 text-[10px] font-black uppercase tracking-widest text-center py-10">No sessions recorded</p>
            ) : library.map(song => (
              <button 
                key={song.id}
                onClick={() => setActiveSong(song)}
                className={`w-full text-left p-4 rounded-2xl border transition-all flex items-center gap-4 group ${activeSong?.id === song.id ? 'bg-zinc-800/80 border-zinc-700' : 'bg-zinc-900/20 border-zinc-900'}`}
              >
                <div className="w-11 h-11 bg-zinc-900 rounded-xl flex items-center justify-center group-hover:bg-zinc-800 border border-zinc-800">
                  <Music2 size={18} className="text-pink-500" />
                </div>
                <div className="flex-1 overflow-hidden">
                  <h4 className="font-black truncate text-sm tracking-tight">{song.title}</h4>
                  <div className="text-[9px] text-zinc-600 font-black uppercase tracking-widest italic">{song.genre}</div>
                </div>
              </button>
            ))}
          </div>
        )}
      </aside>

      <main className="flex-1 flex flex-col bg-[#020202]">
        {activeSong ? (
          <div className="flex-1 flex flex-col overflow-hidden">
            <div className="h-20 border-b border-zinc-900 flex items-center px-10 justify-between bg-zinc-950/40 backdrop-blur-2xl">
              <div className="flex items-center gap-8">
                <button 
                  onClick={isPlaying ? stopAll : () => playAll(tracks)}
                  className={`flex items-center gap-3 px-8 py-3 rounded-full font-black text-xs uppercase tracking-[0.2em] transition-all active:scale-95 shadow-2xl ${isPlaying ? 'bg-white text-black' : 'bg-indigo-600 text-white shadow-indigo-600/30'}`}
                >
                  {isPlaying ? <Square size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" />}
                  {isPlaying ? 'Stop Mix' : 'Play Arrangement'}
                </button>

                <div className="flex items-center gap-6 bg-zinc-900/30 px-6 py-2.5 rounded-2xl border border-zinc-800/50">
                   <div className="flex items-center gap-3">
                     <span className="text-[10px] font-black uppercase text-zinc-600 tracking-widest">Tempo</span>
                     <span className="text-pink-500 font-black mono tracking-tighter">{activeSong.bpm}</span>
                   </div>
                   <div className="w-[1px] h-4 bg-zinc-800" />
                   <div className="flex items-center gap-3">
                      <Sparkles size={14} className="text-emerald-500" />
                      <span className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Master Glue Active</span>
                   </div>
                </div>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-10 custom-scrollbar bg-[radial-gradient(circle_at_top,_#0a0a1a,_transparent)]">
              <div className="mb-12">
                <h1 className="text-6xl font-black tracking-tighter mb-2 italic bg-clip-text text-transparent bg-gradient-to-r from-white via-zinc-400 to-zinc-700">{activeSong.title}</h1>
                <p className="text-zinc-600 font-black uppercase tracking-[0.6em] text-[9px] ml-1">Authentic Performance Engine • Parallel Synthesis</p>
              </div>

              <div className="grid grid-cols-1 gap-5">
                {tracks.map(track => (
                  <div key={track.id} className="flex gap-6 items-center bg-zinc-950/40 p-2 pr-8 rounded-3xl border border-zinc-900/80 hover:border-zinc-800/80 transition-all group relative overflow-hidden">
                    <div className="w-52 p-4 flex flex-col gap-3 z-10">
                      <div className="flex items-center gap-3">
                        <div className="w-3 h-3 rounded-full shadow-[0_0_10px_currentColor]" style={{ color: track.color, backgroundColor: 'currentColor' }} />
                        <span className="font-black uppercase tracking-widest text-[11px] text-zinc-400 truncate">{track.name}</span>
                      </div>
                      <div className="flex gap-2">
                        <button onClick={() => handleUpdateTrack(track.id, { isMuted: !track.isMuted })} className={`text-[9px] font-black px-3 py-1.5 rounded-xl border transition-colors ${track.isMuted ? 'bg-red-600 border-red-500 text-white' : 'bg-zinc-900 border-zinc-800 text-zinc-600 hover:text-zinc-400'}`}>MUTE</button>
                        <button onClick={() => handleUpdateTrack(track.id, { isSolo: !track.isSolo })} className={`text-[9px] font-black px-3 py-1.5 rounded-xl border transition-colors ${track.isSolo ? 'bg-yellow-500 border-yellow-400 text-zinc-950' : 'bg-zinc-900 border-zinc-800 text-zinc-600 hover:text-zinc-400'}`}>SOLO</button>
                      </div>
                    </div>

                    <div className="flex-1 h-24 bg-black/60 rounded-[2rem] border border-zinc-900/50 overflow-hidden relative shadow-inner">
                       <Waveform color={track.color} intensity={track.buffer ? 0.95 : 0.1} isPlaying={isPlaying && !track.isMuted} height={96} />
                       <div className="absolute top-0 right-0 p-4 text-[7px] font-black text-zinc-700 tracking-[0.3em] uppercase">PCM STREAM RAW</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="h-80 border-t border-zinc-900 bg-[#050505]/95 backdrop-blur-3xl p-8 flex gap-6 overflow-x-auto custom-scrollbar items-end shadow-[0_-20px_50px_rgba(0,0,0,0.5)]">
               {tracks.map(track => (
                 <MixerTrack key={track.id} track={track} onUpdate={handleUpdateTrack} isPlaying={isPlaying} />
               ))}
               <div className="flex flex-col items-center bg-zinc-900/40 rounded-3xl p-6 w-36 border-2 border-zinc-800/50 ml-auto h-full justify-between shadow-2xl relative">
                <div className="absolute top-2 text-[8px] font-black text-pink-500/50 tracking-widest">ANALOG BUS</div>
                <Volume2 size={24} className="text-zinc-600 mt-4" />
                <div className="flex-1 w-full flex justify-center py-6 relative">
                   <div className="w-1 bg-zinc-800 h-full absolute rounded-full" />
                   <div className="absolute bottom-6 w-2 bg-gradient-to-t from-pink-600 via-indigo-600 to-indigo-400 h-3/4 rounded-full blur-[2px] opacity-40 shadow-[0_0_20px_#4f46e5]" />
                   <input type="range" className="appearance-none bg-transparent w-44 -rotate-90 absolute top-1/2 cursor-pointer [&::-webkit-slider-thumb]:w-5 [&::-webkit-slider-thumb]:h-5 [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:shadow-xl" />
                </div>
                <span className="text-[10px] font-black text-zinc-400 uppercase tracking-widest italic">MASTER</span>
               </div>
            </div>
          </div>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center p-16 text-center">
            <div className="relative mb-12">
               <div className="absolute inset-0 bg-pink-500 blur-[80px] opacity-10 animate-pulse" />
               <Disc className="text-zinc-800 animate-spin-slow relative" size={160} />
               <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-pink-500" size={48} />
            </div>
            <h2 className="text-5xl font-black tracking-tighter mb-4 uppercase italic text-transparent bg-clip-text bg-gradient-to-b from-white to-zinc-700">Aether Realistic Engine</h2>
            <p className="text-zinc-600 max-w-sm mx-auto mb-10 text-sm leading-relaxed font-black uppercase tracking-widest">
              Multi-Stem Parallel Synthesis • Stereo Spatialization • Analog Saturation Glue
            </p>
            <button onClick={() => setSidebarView('create')} className="bg-white text-black px-12 py-5 rounded-3xl font-black text-xs uppercase tracking-[0.3em] flex items-center gap-4 hover:scale-105 transition-all shadow-2xl active:scale-95 group">
              <Sparkles size={22} className="group-hover:rotate-12 transition-transform" /> Start Band Session
            </button>
          </div>
        )}
      </main>

      {isGenerating && (
        <div className="fixed inset-0 bg-black/98 backdrop-blur-3xl z-[100] flex flex-col items-center justify-center">
           <Disc className="text-pink-600 animate-spin-slow mb-12 shadow-[0_0_100px_#db277730]" size={140} />
           <div className="flex flex-col items-center gap-2">
             <h2 className="text-4xl font-black tracking-tighter uppercase italic text-transparent bg-clip-text bg-gradient-to-r from-white via-pink-500 to-indigo-600 animate-pulse">
               {generationStep}
             </h2>
             <div className="h-1 w-64 bg-zinc-900 rounded-full mt-4 overflow-hidden">
                <div className="h-full bg-pink-600 animate-shimmer w-1/3" />
             </div>
           </div>
           <p className="mt-8 text-zinc-600 font-black uppercase tracking-[0.8em] text-[9px] animate-pulse">Building Multi-Track PCM Buffers</p>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; height: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1a1a1a; border-radius: 10px; }
        @keyframes spin-slow { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .animate-spin-slow { animation: spin-slow 20s linear infinite; }
        @keyframes shimmer { 0% { transform: translateX(-100%); } 100% { transform: translateX(300%); } }
        .animate-shimmer { animation: shimmer 2s infinite ease-in-out; }
      `}</style>
    </div>
  );
};

export default App;

export enum StemType {
  VOCALS = 'VOCALS',
  DRUMS = 'DRUMS',
  BASS = 'BASS',
  SYNTH = 'SYNTH',
  PADS = 'PADS',
  GUITAR = 'GUITAR',
  PIANO = 'PIANO'
}

export interface SongStructure {
  id: string;
  title: string;
  bpm: number;
  key: string;
  genre: string;
  lyrics: {
    verse: string;
    chorus: string;
    bridge: string;
  };
  stems: Array<{
    type: StemType;
    description: string;
    performance_instruction: string;
    intensity: number;
  }>;
  vocalGender: 'Male' | 'Female' | 'Non-binary';
  createdAt: number;
}

export interface AudioTrack {
  id: string;
  name: string;
  type: StemType;
  buffer?: AudioBuffer;
  volume: number;
  pan: number; // -1 to 1
  isMuted: boolean;
  isSolo: boolean;
  color: string;
}

export interface GenerationParams {
  lyrics: string;
  style: string;
  vocalGender: string;
  vocalStyle: string;
  instruments: string[];
}

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { 
  Play, 
  Square, 
  Settings2, 
  Music2, 
  Save, 
  Wand2, 
  Loader2,
  Share2,
  Trash2,
  Volume2,
  Disc,
  Library,
  Home,
  Compass,
  Plus,
  ChevronRight,
  Clock,
  CheckCircle2,
  Sparkles,
  Zap,
  Mic2
} from 'lucide-react';
import { generateSongStructure, synthesizeStemAudio, decodeAudioData } from './services/geminiService';
import { SongStructure, AudioTrack, StemType, GenerationParams } from './types';
import { STEM_CONFIG } from './constants';
import Waveform from './components/Waveform';
import MixerTrack from './components/MixerTrack';

const App: React.FC = () => {
  const [params, setParams] = useState<GenerationParams>({
    lyrics: '',
    style: '',
    vocalGender: 'Female',
    vocalStyle: 'Powerful',
    instruments: ['Drums', 'Bass', 'Vocals', 'Synths', 'Pads']
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState<string>('');
  const [activeSong, setActiveSong] = useState<SongStructure | null>(null);
  const [library, setLibrary] = useState<SongStructure[]>([]);
  const [tracks, setTracks] = useState<AudioTrack[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [sidebarView, setSidebarView] = useState<'create' | 'library'>('create');

  const audioCtxRef = useRef<AudioContext | null>(null);
  const sourceNodesRef = useRef<Map<string, AudioBufferSourceNode>>(new Map());
  const gainNodesRef = useRef<Map<string, GainNode>>(new Map());
  const panNodesRef = useRef<Map<string, PannerNode>>(new Map());
  const masterCompressorRef = useRef<DynamicsCompressorNode | null>(null);
  const masterSaturationRef = useRef<WaveShaperNode | null>(null);

  const initAudio = () => {
    if (!audioCtxRef.current) {
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioCtxRef.current = ctx;

      const compressor = ctx.createDynamicsCompressor();
      compressor.threshold.setValueAtTime(-24, ctx.currentTime);
      compressor.knee.setValueAtTime(30, ctx.currentTime);
      compressor.ratio.setValueAtTime(12, ctx.currentTime);
      compressor.attack.setValueAtTime(0.003, ctx.currentTime);
      compressor.release.setValueAtTime(0.25, ctx.currentTime);
      masterCompressorRef.current = compressor;

      const shaper = ctx.createWaveShaper();
      const curve = new Float32Array(44100);
      const k = 0.45;
      for (let i = 0; i < 44100; i++) {
        const x = (i * 2) / 44100 - 1;
        curve[i] = ((1 + k) * x) / (1 + k * Math.abs(x));
      }
      shaper.curve = curve;
      shaper.oversample = '4x';

      compressor.connect(shaper);
      shaper.connect(ctx.destination);
      masterSaturationRef.current = shaper;
    }
  };

  const stopAll = useCallback(() => {
    setIsPlaying(false);
    sourceNodesRef.current.forEach(node => {
      try { node.stop(); } catch(e) {}
    });
    sourceNodesRef.current.clear();
  }, []);

  const playAll = useCallback(async (currentTracks: AudioTrack[]) => {
    initAudio();
    if (!audioCtxRef.current || currentTracks.length === 0) return;
    if (audioCtxRef.current.state === 'suspended') await audioCtxRef.current.resume();

    stopAll();
    const ctx = audioCtxRef.current!;
    const globalStartTime = ctx.currentTime + 0.5;
    setIsPlaying(true);

    const anySolo = currentTracks.some(t => t.isSolo);

    currentTracks.forEach(track => {
      if (track.buffer) {
        const source = ctx.createBufferSource();
        source.buffer = track.buffer;

        let gainNode = gainNodesRef.current.get(track.id);
        if (!gainNode) {
          gainNode = ctx.createGain();
          gainNodesRef.current.set(track.id, gainNode);
        }

        let targetGain = track.volume;
        if (track.isMuted) targetGain = 0;
        if (anySolo && !track.isSolo) targetGain = 0;
        gainNode.gain.setValueAtTime(targetGain, ctx.currentTime);

        let panNode = panNodesRef.current.get(track.id);
        if (!panNode) {
          panNode = ctx.createPanner();
          panNode.panningModel = 'equalpower';
          panNodesRef.current.set(track.id, panNode);
        }
        panNode.positionX.setValueAtTime(track.pan, ctx.currentTime);

        source.connect(panNode);
        panNode.connect(gainNode);
        gainNode.connect(masterCompressorRef.current!);

        const jitter = (Math.random() - 0.5) * 0.055; 
        const humanStartTime = globalStartTime + jitter;

        source.loop = true;
        source.start(humanStartTime);
        sourceNodesRef.current.set(track.id, source);
      }
    });
  }, [stopAll]);

  const handleUpdateTrack = (id: string, updates: Partial<AudioTrack>) => {
    setTracks(prev => {
      const nextTracks = prev.map(t => t.id === id ? { ...t, ...updates } : t);
      const anySolo = nextTracks.some(t => t.isSolo);

      nextTracks.forEach(track => {
        const gain = gainNodesRef.current.get(track.id);
        if (gain) {
          let targetGain = track.volume;
          if (track.isMuted) targetGain = 0;
          if (anySolo && !track.isSolo) targetGain = 0;
          gain.gain.setTargetAtTime(targetGain, audioCtxRef.current?.currentTime || 0, 0.05);
        }
        const pan = panNodesRef.current.get(track.id);
        if (pan) {
          pan.positionX.setTargetAtTime(track.pan, audioCtxRef.current?.currentTime || 0, 0.08);
        }
      });
      return nextTracks;
    });
  };

  const handleGenerate = async () => {
    if (!params.style || !params.lyrics) {
      setError("Provide a musical direction and lyrics for the band to perform.");
      return;
    }
    initAudio();
    setIsGenerating(true);
    setError(null);
    stopAll();

    try {
      setGenerationStep('Writing Arrangement...');
      const structure = await generateSongStructure(params);

      const synthesisPromises = structure.stems.map(async (stem, index) => {
        setGenerationStep(`Recording ${stem.type}...`);

        const instruction = stem.type === StemType.VOCALS 
          ? structure.lyrics.chorus 
          : stem.performance_instruction;

        const audioBytes = await synthesizeStemAudio(instruction, stem.type as StemType, {
          genre: structure.genre,
          bpm: structure.bpm,
          key: structure.key,
          vocalStyle: params.vocalStyle
        });

        const buffer = await decodeAudioData(audioBytes, audioCtxRef.current!);

        let defaultPan = 0;
        if (stem.type === StemType.SYNTH) defaultPan = -0.55;
        if (stem.type === StemType.PADS) defaultPan = 0.55;
        if (stem.type === StemType.GUITAR) defaultPan = -0.3;
        if (stem.type === StemType.PIANO) defaultPan = 0.3;

        return {
          id: `stem-${index}-${Date.now()}`,
          name: `${stem.type}`,
          type: stem.type as StemType,
          buffer: buffer, 
          volume: stem.type === StemType.VOCALS ? 0.95 : stem.type === StemType.DRUMS ? 0.7 : 0.55,
          pan: defaultPan,
          isMuted: false,
          isSolo: false,
          color: STEM_CONFIG[stem.type as StemType].color
        };
      });

      const tracksResult = await Promise.all(synthesisPromises);
      setTracks(tracksResult);
      setActiveSong(structure);
      setLibrary(prev => [structure, ...prev]);
      playAll(tracksResult);

    } catch (err: any) {
      console.error(err);
      setError("Band session failed. Ensure your connection is stable.");
