import { GoogleGenAI, Type, Modality } from "@google/genai";
import { SongStructure, StemType, GenerationParams } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateSongStructure = async (params: GenerationParams): Promise<SongStructure> => {
  const prompt = `
    You are a legendary Music Producer. Compose a professional song structure for a virtual AI band.
    - User Concept: "${params.lyrics}"
    - Style: "${params.style}"
    - Vocal Gender: "${params.vocalGender}"
    - Vocal Performance Style: "${params.vocalStyle}"
    - Instruments: "${params.instruments.join(', ')}"

    CRITICAL REALISM REQUIREMENTS:
    1. The lyrics must be professional (verse, chorus, bridge).
    2. Provide a BPM (80-140) and Key.
    3. Define EXACTLY 5 stems: VOCALS, DRUMS, BASS, SYNTH, PADS.
    4. For each instrumental stem (excluding VOCALS), provide a "performance_instruction".
       IMPORTANT: The "performance_instruction" must be a PHONETIC SCRIPT (onomatopoeia) that a human would say to mimic the instrument.
       - DRUMS: Use words like "boom", "tch", "kack", "shhh" (e.g., "boom kack boom-boom kack").
       - BASS: Use deep rhythmic sounds like "doom", "doob", "da-da" (e.g., "doom doob doom-da-doom").
       - SYNTH/PADS: Use melodic vocalizations like "vwaaa", "ooooh", "shimmer" (e.g., "vwaaaah ooooh shimmer").

    Return a valid JSON object with: title, bpm, key, genre, lyrics, and stems array.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          genre: { type: Type.STRING },
          lyrics: {
            type: Type.OBJECT,
            properties: {
              verse: { type: Type.STRING },
              chorus: { type: Type.STRING },
              bridge: { type: Type.STRING }
            },
            required: ['verse', 'chorus', 'bridge']
          },
          stems: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, enum: Object.values(StemType) },
                description: { type: Type.STRING },
                performance_instruction: { type: Type.STRING },
                intensity: { type: Type.NUMBER }
              },
              required: ['type', 'description', 'performance_instruction', 'intensity']
            }
          }
        },
        required: ['title', 'bpm', 'key', 'genre', 'lyrics', 'stems']
      }
    }
  });

  const textResponse = response.text;
  if (!textResponse) throw new Error("Failed to get a response from the model.");

  const parsed = JSON.parse(textResponse);
  return {
    ...parsed,
    id: crypto.randomUUID(),
    vocalGender: params.vocalGender as any,
    createdAt: Date.now()
  };
};

export const synthesizeStemAudio = async (
  instruction: string, 
  type: StemType, 
  context: { genre: string, bpm: number, key: string, vocalStyle?: string }
): Promise<Uint8Array> => {
  // Select voices that characteristically fit the instrument's frequency range
  const voice = type === StemType.BASS ? 'Fenrir' : type === StemType.VOCALS ? 'Kore' : 'Zephyr';

  let performancePrompt = "";
  if (type === StemType.VOCALS) {
    performancePrompt = `Sing this chorus with a ${context.vocalStyle || 'natural'} vocal delivery, incorporating deep emotion, breath-work, and realistic phrasing in ${context.genre} style at ${context.bpm} BPM in ${context.key}. 
    Lyrics: ${instruction}`;
  } else {
    // For instruments, we treat the instruction as a phonetic script to ensure the TTS model actually produces sound.
    performancePrompt = `You are performing the ${type} part of a ${context.genre} song. 
    Using only your voice, perform this rhythmic phonetic script with musical conviction: "${instruction}".
    Tempo is ${context.bpm} BPM. Key is ${context.key}.
    DO NOT say anything other than the musical sounds. No intro, no explanation. Just the performance.`;
  }

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: performancePrompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voice },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) {
    // Fallback logic if the primary synthesis fails: try a simpler prompt.
    const retryResponse = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Perform the following musical sounds rhythmically: ${instruction}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voice },
          },
        },
      },
    });
    const fallbackBase64 = retryResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!fallbackBase64) throw new Error(`Synthesis failed for ${type} even after retry.`);
    return decodeBase64(fallbackBase64);
  }

  return decodeBase64(base64Audio);
};

function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { SongStructure, StemType, GenerationParams } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateSongStructure = async (params: GenerationParams): Promise<SongStructure> => {
  const prompt = `
    You are a professional Music Director for an AI Band. Create a song arrangement based on:
    - Concept: "${params.lyrics}"
    - Style: "${params.style}"
    - Vocal Character: ${params.vocalGender}, Style: ${params.vocalStyle}

    Requirements:
    1. Write 5 specific stems: VOCALS, DRUMS, BASS, SYNTH, PADS.
    2. For VOCALS, provide the lyric snippet.
    3. For others, provide a PHONETIC onomatopoeia script for a vocal performance.
       - DRUMS: rhythmic "boom-tss-kack" style patterns.
       - BASS: deep "dum-dum-doom" melodic humming.
       - SYNTH/PADS: airy "vwaaaaa-ooooh" textures.

    Return valid JSON.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          genre: { type: Type.STRING },
          lyrics: {
            type: Type.OBJECT,
            properties: {
              verse: { type: Type.STRING },
              chorus: { type: Type.STRING },
              bridge: { type: Type.STRING }
            },
            required: ['verse', 'chorus', 'bridge']
          },
          stems: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, enum: Object.values(StemType) },
                description: { type: Type.STRING },
                performance_instruction: { type: Type.STRING },
                intensity: { type: Type.NUMBER }
              },
              required: ['type', 'description', 'performance_instruction', 'intensity']
            }
          }
        },
        required: ['title', 'bpm', 'key', 'genre', 'lyrics', 'stems']
      }
    }
  });

  if (!response.text) throw new Error("No structure generated.");
  const parsed = JSON.parse(response.text);

  return {
    ...parsed,
    id: crypto.randomUUID(),
    vocalGender: params.vocalGender as any,
    createdAt: Date.now()
  };
};

export const synthesizeStemAudio = async (
  instruction: string, 
  type: StemType, 
  context: { genre: string, bpm: number, key: string, vocalStyle?: string }
): Promise<Uint8Array> => {
  const voice = type === StemType.BASS ? 'Fenrir' : type === StemType.VOCALS ? 'Kore' : 'Zephyr';

  const performancePrompt = type === StemType.VOCALS 
    ? `Sing these lyrics emotionally in a ${context.vocalStyle} style for a ${context.genre} track at ${context.bpm} BPM: "${instruction}"`
    : `Perform a vocal impression of a ${type} part for a ${context.genre} song. 
       Tempo: ${context.bpm} BPM. Key: ${context.key}. 
       Perform ONLY these rhythmic sounds: "${instruction}". 
       No speaking, only the musical vocalization.`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: performancePrompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voice },
        },
      },
    },
  });

  // Iterate to find the actual audio part, as model may return text parts too
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData?.data) {
        return decodeBase64(part.inlineData.data);
      }
    }
  }

  throw new Error(`No audio data returned for ${type}`);
};

function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useState, useRef, useCallback } from 'react';
import { 
  Play, 
  Square, 
  Settings2, 
  Music2, 
  Volume2, 
  Disc, 
  Library, 
  Home, 
  Sparkles, 
  Zap, 
  Mic2,
  AlertCircle
} from 'lucide-react';
import { generateSongStructure, synthesizeStemAudio, decodeAudioData } from './services/geminiService';
import { SongStructure, AudioTrack, StemType, GenerationParams } from './types';
import { STEM_CONFIG } from './constants';
import Waveform from './components/Waveform';
import MixerTrack from './components/MixerTrack';

const App: React.FC = () => {
  const [params, setParams] = useState<GenerationParams>({
    lyrics: '',
    style: '',
    vocalGender: 'Female',
    vocalStyle: 'Powerful',
    instruments: ['Drums', 'Bass', 'Vocals', 'Synths', 'Pads']
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState<string>('');
  const [activeSong, setActiveSong] = useState<SongStructure | null>(null);
  const [library, setLibrary] = useState<SongStructure[]>([]);
  const [tracks, setTracks] = useState<AudioTrack[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [sidebarView, setSidebarView] = useState<'create' | 'library'>('create');

  const audioCtxRef = useRef<AudioContext | null>(null);
  const sourceNodesRef = useRef<Map<string, AudioBufferSourceNode>>(new Map());
  const gainNodesRef = useRef<Map<string, GainNode>>(new Map());
  const panNodesRef = useRef<Map<string, PannerNode>>(new Map());
  const masterCompressorRef = useRef<DynamicsCompressorNode | null>(null);
  const masterSaturationRef = useRef<WaveShaperNode | null>(null);

  const initAudio = () => {
    if (!audioCtxRef.current) {
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioCtxRef.current = ctx;

      const compressor = ctx.createDynamicsCompressor();
      compressor.threshold.setValueAtTime(-24, ctx.currentTime);
      compressor.knee.setValueAtTime(30, ctx.currentTime);
      compressor.ratio.setValueAtTime(12, ctx.currentTime);
      compressor.attack.setValueAtTime(0.003, ctx.currentTime);
      compressor.release.setValueAtTime(0.25, ctx.currentTime);
      masterCompressorRef.current = compressor;

      const shaper = ctx.createWaveShaper();
      const curve = new Float32Array(44100);
      const k = 0.45;
      for (let i = 0; i < 44100; i++) {
        const x = (i * 2) / 44100 - 1;
        curve[i] = ((1 + k) * x) / (1 + k * Math.abs(x));
      }
      shaper.curve = curve;
      shaper.oversample = '4x';

      compressor.connect(shaper);
      shaper.connect(ctx.destination);
      masterSaturationRef.current = shaper;
    }
  };

  const stopAll = useCallback(() => {
    setIsPlaying(false);
    sourceNodesRef.current.forEach(node => {
      try { node.stop(); } catch(e) {}
    });
    sourceNodesRef.current.clear();
  }, []);

  const playAll = useCallback(async (currentTracks: AudioTrack[]) => {
    initAudio();
    if (!audioCtxRef.current || currentTracks.length === 0) return;
    if (audioCtxRef.current.state === 'suspended') await audioCtxRef.current.resume();

    stopAll();
    const ctx = audioCtxRef.current!;
    const globalStartTime = ctx.currentTime + 0.1;
    setIsPlaying(true);

    const anySolo = currentTracks.some(t => t.isSolo);

    currentTracks.forEach(track => {
      if (track.buffer && masterCompressorRef.current) {
        const source = ctx.createBufferSource();
        source.buffer = track.buffer;

        let gainNode = gainNodesRef.current.get(track.id);
        if (!gainNode) {
          gainNode = ctx.createGain();
          gainNodesRef.current.set(track.id, gainNode);
        }

        const targetGain = track.isMuted ? 0 : (anySolo && !track.isSolo ? 0 : track.volume);
        gainNode.gain.setValueAtTime(targetGain, ctx.currentTime);

        let panNode = panNodesRef.current.get(track.id);
        if (!panNode) {
          panNode = ctx.createPanner();
          panNode.panningModel = 'equalpower';
          panNodesRef.current.set(track.id, panNode);
        }
        panNode.positionX.setValueAtTime(track.pan, ctx.currentTime);

        source.connect(panNode);
        panNode.connect(gainNode);
        gainNode.connect(masterCompressorRef.current);

        source.loop = true;
        source.start(globalStartTime);
        sourceNodesRef.current.set(track.id, source);
      }
    });
  }, [stopAll]);

  const handleUpdateTrack = (id: string, updates: Partial<AudioTrack>) => {
    setTracks(prev => {
      const nextTracks = prev.map(t => t.id === id ? { ...t, ...updates } : t);
      const anySolo = nextTracks.some(t => t.isSolo);

      nextTracks.forEach(track => {
        const gain = gainNodesRef.current.get(track.id);
        if (gain) {
          const targetGain = track.isMuted ? 0 : (anySolo && !track.isSolo ? 0 : track.volume);
          gain.gain.setTargetAtTime(targetGain, audioCtxRef.current?.currentTime || 0, 0.05);
        }
        const pan = panNodesRef.current.get(track.id);
        if (pan) {
          pan.positionX.setTargetAtTime(track.pan, audioCtxRef.current?.currentTime || 0, 0.08);
        }
      });
      return nextTracks;
    });
  };

  const handleGenerate = async () => {
    if (!params.style || !params.lyrics) {
      setError("Please provide both lyrics and a musical style.");
      return;
    }
    initAudio();
    setIsGenerating(true);
    setError(null);
    stopAll();

    try {
      setGenerationStep('Designing Song Structure...');
      const structure = await generateSongStructure(params);

      const tracksToBuild: AudioTrack[] = [];

      for (const [index, stem] of structure.stems.entries()) {
        setGenerationStep(`Recording ${stem.type}...`);
        try {
          const instruction = stem.type === StemType.VOCALS 
            ? structure.lyrics.chorus 
            : stem.performance_instruction;

          const audioBytes = await synthesizeStemAudio(instruction, stem.type as StemType, {
            genre: structure.genre,
            bpm: structure.bpm,
            key: structure.key,
            vocalStyle: params.vocalStyle
          });

          const buffer = await decodeAudioData(audioBytes, audioCtxRef.current!);

          let defaultPan = 0;
          if (stem.type === StemType.SYNTH) defaultPan = -0.5;
          if (stem.type === StemType.PADS) defaultPan = 0.5;

          tracksToBuild.push({
            id: `stem-${index}-${Date.now()}`,
            name: stem.type,
            type: stem.type as StemType,
            buffer: buffer,
            volume: stem.type === StemType.VOCALS ? 0.9 : 0.6,
            pan: defaultPan,
            isMuted: false,
            isSolo: false,
            color: STEM_CONFIG[stem.type as StemType].color
          });
        } catch (stemError) {
          console.warn(`Failed to synthesize stem: ${stem.type}`, stemError);
        }
      }

      if (tracksToBuild.length === 0) throw new Error("Could not synthesize any stems.");

      setTracks(tracksToBuild);
      setActiveSong(structure);
      setLibrary(prev => [structure, ...prev]);
      playAll(tracksToBuild);

    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred during generation.");
    } finally {
      setIsGenerating(false);
      setGenerationStep('');
    }
  };

  const VOCAL_STYLES = [
    { id: 'Powerful', label: 'Powerful', desc: 'Bold delivery' },
    { id: 'Soft', label: 'Soft', desc: 'Breathy, intimate' },
    { id: 'Raspy', label: 'Raspy', desc: 'Gritty texture' },
    { id: 'Soulful', label: 'Soulful', desc: 'Melodic R&B' }
  ];

  return (
    <div className="flex h-screen bg-[#020202] text-zinc-100 font-sans selection:bg-pink-500/30">
      <nav className="w-16 border-r border-zinc-900 flex flex-col items-center py-6 gap-8 bg-zinc-950/50 backdrop-blur-md">
        <div className="w-10 h-10 bg-gradient-to-tr from-pink-600 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-pink-600/20">
          <Disc className="text-white animate-spin-slow" size={20} />
        </div>
        <div className="flex flex-col gap-6">
          <button onClick={() => setSidebarView('create')} className={`p-2.5 rounded-xl transition-all ${sidebarView === 'create' ? 'bg-zinc-800 text-white shadow-inner' : 'text-zinc-600 hover:text-zinc-300'}`}>
            <Home size={22} />
          </button>
          <button onClick={() => setSidebarView('library')} className={`p-2.5 rounded-xl transition-all ${sidebarView === 'library' ? 'bg-zinc-800 text-white shadow-inner' : 'text-zinc-600 hover:text-zinc-300'}`}>
            <Library size={22} />
          </button>
        </div>
      </nav>

      <aside className="w-[380px] border-r border-zinc-900 bg-[#050505] flex flex-col overflow-y-auto custom-scrollbar shadow-2xl">
        {sidebarView === 'create' ? (
          <div className="p-7 space-y-8">
            <header>
              <h2 className="text-2xl font-black tracking-tight mb-1 uppercase italic">Aether Studio</h2>
              <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.2em]">Music Generation Suite</p>
            </header>

            <div className="space-y-6">
              <div className="space-y-2.5">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Lyrics / Theme</label>
                <textarea 
                  value={params.lyrics}
                  onChange={(e) => setParams({...params, lyrics: e.target.value})}
                  placeholder="The vocalist will interpret these..."
                  className="w-full h-32 bg-zinc-900/30 border border-zinc-800/80 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-pink-500/30 focus:border-pink-500/50 transition-all outline-none resize-none"
                />
              </div>

              <div className="space-y-2.5">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Musical Style</label>
                <input 
                  value={params.style}
                  onChange={(e) => setParams({...params, style: e.target.value})}
                  placeholder="e.g. 80s Synthwave, Soul, Indie Rock"
                  className="w-full bg-zinc-900/30 border border-zinc-800/80 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-pink-500/30 focus:border-pink-500/50 transition-all outline-none"
                />
              </div>

              <div className="space-y-4">
                <div className="space-y-2.5">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Vocal Gender</label>
                  <div className="grid grid-cols-3 gap-2">
                    {['Female', 'Male', 'Non-binary'].map(g => (
                      <button 
                        key={g}
                        onClick={() => setParams({...params, vocalGender: g})}
                        className={`py-2 px-1 rounded-xl border text-[10px] font-black uppercase transition-all ${params.vocalGender === g ? 'bg-pink-600 border-pink-500 text-white' : 'bg-zinc-900/40 border-zinc-800 text-zinc-500'}`}
                      >
                        {g}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-2.5">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1 flex items-center gap-2">
                    Vocal Style <Mic2 size={12} className="text-pink-500" />
                  </label>
                  <div className="grid grid-cols-2 gap-2">
                    {VOCAL_STYLES.map(s => (
                      <button 
                        key={s.id}
                        onClick={() => setParams({...params, vocalStyle: s.id})}
                        className={`text-left p-3 rounded-xl border transition-all ${params.vocalStyle === s.id ? 'bg-indigo-600/20 border-indigo-500 text-white shadow-lg' : 'bg-zinc-900/40 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
                      >
                        <span className="text-[10px] font-black uppercase block">{s.label}</span>
                        <span className="text-[8px] opacity-60 font-medium">{s.desc}</span>
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              {error && (
                <div className="p-3 bg-red-900/20 border border-red-800/50 rounded-xl flex items-center gap-3 text-red-400 text-xs">
                  <AlertCircle size={16} />
                  <span>{error}</span>
                </div>
              )}

              <button 
                onClick={handleGenerate}
                disabled={isGenerating}
                className="group relative w-full bg-white text-black py-5 rounded-2xl font-black uppercase tracking-[0.2em] text-xs hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-3 mt-4 disabled:opacity-40"
              >
                <Zap size={18} className="text-indigo-600" />
                {isGenerating ? 'Processing...' : 'Generate Tracks'}
              </button>
            </div>
          </div>
        ) : (
          <div className="p-7 space-y-6">
            <h2 className="text-2xl font-black tracking-tight">Library</h2>
            {library.length === 0 ? (
              <p className="text-zinc-600 text-[10px] font-black uppercase text-center py-10">Empty</p>
            ) : library.map(song => (
              <button 
                key={song.id}
                onClick={() => setActiveSong(song)}
                className={`w-full text-left p-4 rounded-2xl border transition-all flex items-center gap-4 group ${activeSong?.id === song.id ? 'bg-zinc-800/80 border-zinc-700' : 'bg-zinc-900/20 border-zinc-900'}`}
              >
                <div className="w-10 h-10 bg-zinc-900 rounded-xl flex items-center justify-center group-hover:bg-zinc-800 border border-zinc-800">
                  <Music2 size={16} className="text-pink-500" />
                </div>
                <div className="flex-1 overflow-hidden">
                  <h4 className="font-black truncate text-sm tracking-tight">{song.title}</h4>
                  <div className="text-[9px] text-zinc-600 font-black uppercase tracking-widest italic">{song.genre}</div>
                </div>
              </button>
            ))}
          </div>
        )}
      </aside>

      <main className="flex-1 flex flex-col bg-[#020202]">
        {activeSong ? (
          <div className="flex-1 flex flex-col overflow-hidden">
            <div className="h-20 border-b border-zinc-900 flex items-center px-10 justify-between bg-zinc-950/40 backdrop-blur-2xl">
              <div className="flex items-center gap-8">
                <button 
                  onClick={isPlaying ? stopAll : () => playAll(tracks)}
                  className={`flex items-center gap-3 px-8 py-3 rounded-full font-black text-xs uppercase tracking-[0.2em] transition-all active:scale-95 shadow-2xl ${isPlaying ? 'bg-white text-black' : 'bg-indigo-600 text-white shadow-indigo-600/30'}`}
                >
                  {isPlaying ? <Square size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" />}
                  {isPlaying ? 'Stop' : 'Play'}
                </button>

                <div className="flex items-center gap-6 bg-zinc-900/30 px-6 py-2.5 rounded-2xl border border-zinc-800/50">
                   <div className="flex items-center gap-3">
                     <span className="text-[10px] font-black uppercase text-zinc-600 tracking-widest">BPM</span>
                     <span className="text-pink-500 font-black mono">{activeSong.bpm}</span>
                   </div>
                   <div className="flex items-center gap-3">
                      <Sparkles size={14} className="text-emerald-500" />
                      <span className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Processing Live</span>
                   </div>
                </div>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-10 custom-scrollbar bg-[radial-gradient(circle_at_top,_#0a0a1a,_transparent)]">
              <div className="mb-12">
                <h1 className="text-6xl font-black tracking-tighter mb-2 italic bg-clip-text text-transparent bg-gradient-to-r from-white via-zinc-400 to-zinc-700">{activeSong.title}</h1>
                <p className="text-zinc-600 font-black uppercase tracking-[0.6em] text-[9px] ml-1">Multi-Stem Synthesis Output</p>
              </div>

              <div className="grid grid-cols-1 gap-5">
                {tracks.map(track => (
                  <div key={track.id} className="flex gap-6 items-center bg-zinc-950/40 p-2 pr-8 rounded-3xl border border-zinc-900/80 hover:border-zinc-800/80 transition-all group relative overflow-hidden">
                    <div className="w-48 p-4 flex flex-col gap-3 z-10">
                      <div className="flex items-center gap-3">
                        <div className="w-3 h-3 rounded-full" style={{ backgroundColor: track.color }} />
                        <span className="font-black uppercase tracking-widest text-[11px] text-zinc-400 truncate">{track.name}</span>
                      </div>
                      <div className="flex gap-2">
                        <button onClick={() => handleUpdateTrack(track.id, { isMuted: !track.isMuted })} className={`text-[9px] font-black px-3 py-1.5 rounded-xl border ${track.isMuted ? 'bg-red-600 border-red-500 text-white' : 'bg-zinc-900 border-zinc-800 text-zinc-600'}`}>MUTE</button>
                        <button onClick={() => handleUpdateTrack(track.id, { isSolo: !track.isSolo })} className={`text-[9px] font-black px-3 py-1.5 rounded-xl border ${track.isSolo ? 'bg-yellow-500 border-yellow-400 text-zinc-950' : 'bg-zinc-900 border-zinc-800 text-zinc-600'}`}>SOLO</button>
                      </div>
                    </div>

                    <div className="flex-1 h-20 bg-black/60 rounded-2xl border border-zinc-900/50 overflow-hidden relative shadow-inner">
                       <Waveform color={track.color} intensity={track.buffer ? 0.9 : 0.1} isPlaying={isPlaying && !track.isMuted} height={80} />
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="h-80 border-t border-zinc-900 bg-[#050505]/95 backdrop-blur-3xl p-8 flex gap-6 overflow-x-auto custom-scrollbar items-end shadow-2xl">
               {tracks.map(track => (
                 <MixerTrack key={track.id} track={track} onUpdate={handleUpdateTrack} isPlaying={isPlaying} />
               ))}
               <div className="flex flex-col items-center bg-zinc-900/40 rounded-3xl p-6 w-32 border-2 border-zinc-800/50 ml-auto h-full justify-between shadow-2xl relative">
                <Volume2 size={24} className="text-zinc-600 mt-4" />
                <div className="flex-1 w-full flex justify-center py-6 relative">
                   <div className="w-1 bg-zinc-800 h-full absolute rounded-full" />
                   <div className="absolute bottom-6 w-2 bg-gradient-to-t from-pink-600 via-indigo-600 to-indigo-400 h-3/4 rounded-full blur-[2px] opacity-40 shadow-[0_0_20px_#4f46e5]" />
                   <input type="range" className="appearance-none bg-transparent w-44 -rotate-90 absolute top-1/2 cursor-pointer" />
                </div>
                <span className="text-[10px] font-black text-zinc-400 uppercase italic">MASTER</span>
               </div>
            </div>
          </div>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center p-16 text-center">
            <Disc className="text-zinc-800 animate-spin-slow mb-8" size={120} />
            <h2 className="text-4xl font-black tracking-tighter mb-4 uppercase italic">Aether Music Studio</h2>
            <p className="text-zinc-600 max-w-sm mx-auto mb-10 text-sm font-black uppercase tracking-widest">
              Multi-Stem Synthesis Engine
            </p>
            <button onClick={() => setSidebarView('create')} className="bg-white text-black px-12 py-5 rounded-3xl font-black text-xs uppercase tracking-[0.3em] flex items-center gap-4 hover:scale-105 transition-all shadow-2xl group">
              <Zap size={22} className="group-hover:rotate-12 transition-transform" /> New Session
            </button>
          </div>
        )}
      </main>

      {isGenerating && (
        <div className="fixed inset-0 bg-black/98 backdrop-blur-3xl z-[100] flex flex-col items-center justify-center">
