export enum StemType {
  VOCALS = 'VOCALS',
  DRUMS = 'DRUMS',
  BASS = 'BASS',
  SYNTH = 'SYNTH',
  PADS = 'PADS',
  GUITAR = 'GUITAR',
  PIANO = 'PIANO'
}

export interface SongStructure {
