             <h2 className="text-4xl font-black tracking-tighter uppercase italic text-transparent bg-clip-text bg-gradient-to-r from-white via-pink-500 to-indigo-600 animate-pulse">
               {generationStep}
             </h2>
             <div className="h-1.5 w-80 bg-zinc-900 rounded-full mt-6 overflow-hidden border border-zinc-800">
                <div className="h-full bg-pink-600 animate-shimmer w-1/3 shadow-[0_0_15px_#db2777]" />
