export enum StemType {
  VOCALS = 'VOCALS',
  DRUMS = 'DRUMS',
  BASS = 'BASS',
  SYNTH = 'SYNTH',
  PADS = 'PADS',
  GUITAR = 'GUITAR',
  PIANO = 'PIANO'
}

export interface SongStructure {
  id: string;
  title: string;
  bpm: number;
  key: string;
  genre: string;
  lyrics: {
    verse: string;
    chorus: string;
    bridge: string;
  };
  stems: Array<{
    type: StemType;
    description: string;
    performance_instruction: string;
    intensity: number;
  }>;
  vocalGender: 'Male' | 'Female' | 'Non-binary';
  createdAt: number;
}

export interface AudioTrack {
  id: string;
  name: string;
  type: StemType;
  buffer?: AudioBuffer;
  volume: number;
  pan: number; // -1 to 1
  isMuted: boolean;
  isSolo: boolean;
  color: string;
  eq: {
    low: number;   // -12 to 12 dB
    mid: number;   // -12 to 12 dB
    high: number;  // -12 to 12 dB
  };
  sidechainSourceId?: string; // ID of the track that triggers ducking
}

export interface GenerationParams {
  lyrics: string;
  style: string;
  key: string;
  scale: 'Major' | 'Minor';
  vocalGender: string;
  vocalStyle: string;
  instruments: string[];
}

export interface SearchResult {
  text: string;
  sources: { title: string; uri: string }[];
}

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { SongStructure, StemType, GenerationParams, SearchResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Search Grounding for up-to-date music trends
 */
export const searchMusicTrends = async (query: string): Promise<SearchResult> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Research current music trends, production styles, and popular sonic palettes related to: "${query}". Provide a concise summary for a producer.`,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
    ?.map((chunk: any) => ({
      title: chunk.web?.title || 'Source',
      uri: chunk.web?.uri || ''
    }))
    .filter((s: any) => s.uri) || [];

  return {
    text: response.text || "No research data found.",
    sources
  };
};

/**
 * Veo Video Generation
 */
export const generateMusicVideo = async (imageParams: { imageBytes: string, prompt: string, ratio: '16:9' | '9:16' }) => {
  const genAI = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  let operation = await genAI.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: imageParams.prompt,
    image: {
      imageBytes: imageParams.imageBytes,
      mimeType: 'image/png',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: imageParams.ratio
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await genAI.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video generation failed.");

  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

/**
 * Fast AI responses for low-latency suggestions
 */
export const getQuickSuggestions = async (lyrics: string): Promise<string[]> => {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-lite-latest',
    contents: `Based on these lyrics: "${lyrics}", suggest 3 short musical styles or genres. Return only a comma-separated list.`,
  });
  return response.text?.split(',').map(s => s.trim()) || [];
};

/**
 * Audio transcription for voice input
 */
export const transcribeAudio = async (base64Audio: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        inlineData: {
          mimeType: 'audio/wav',
          data: base64Audio
        }
      },
      { text: "Transcribe this musical idea or spoken lyric exactly. Only return the transcription." }
    ]
  });
  return response.text || "";
};

export const generateSongStructure = async (params: GenerationParams): Promise<SongStructure> => {
  const prompt = `
    You are a world-class Music Producer. Create a song arrangement based on:
    - Concept: "${params.lyrics}"
    - Style: "${params.style}"
    - Key: ${params.key} ${params.scale}
    - Vocal Character: ${params.vocalGender}, Style: ${params.vocalStyle}

    Requirements for Performance Realism:
    1. Write 5 stems: VOCALS, DRUMS, BASS, SYNTH, PADS.
    2. Stems must have highly nuanced "performance_instruction" strings.
    3. Include dynamics (e.g., [ghost note], [heavy accent], [crescendo]) and timing variations (e.g., [laid back], [driving], [micro-delay]).
    4. For DRUMS: Use complex onomatopoeia like "ts-ts-BOOM [ghost] tchi-KACK".
    5. For BASS: Use deep, sliding vocalizations like "dooooom [slide] da-dum [vibrato]".

    Return valid JSON.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          genre: { type: Type.STRING },
          lyrics: {
            type: Type.OBJECT,
            properties: {
              verse: { type: Type.STRING },
              chorus: { type: Type.STRING },
              bridge: { type: Type.STRING }
            },
            required: ['verse', 'chorus', 'bridge']
          },
          stems: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, enum: Object.values(StemType) },
                description: { type: Type.STRING },
                performance_instruction: { type: Type.STRING },
                intensity: { type: Type.NUMBER }
              },
              required: ['type', 'description', 'performance_instruction', 'intensity']
            }
          }
        },
        required: ['title', 'bpm', 'key', 'genre', 'lyrics', 'stems']
      }
    }
  });

  if (!response.text) throw new Error("No structure generated.");
  const parsed = JSON.parse(response.text);

  return {
    ...parsed,
    id: crypto.randomUUID(),
    vocalGender: params.vocalGender as any,
    createdAt: Date.now()
  };
};

export const synthesizeStemAudio = async (
  instruction: string, 
  type: StemType, 
  context: { genre: string, bpm: number, key: string, vocalStyle?: string }
): Promise<Uint8Array> => {
  const voice = type === StemType.BASS ? 'Fenrir' : type === StemType.VOCALS ? 'Kore' : 'Zephyr';

  const performancePrompt = type === StemType.VOCALS 
    ? `Sing these lyrics with a ${context.vocalStyle} performance in ${context.key} for a ${context.genre} track at ${context.bpm} BPM. 
       Incorporate the specific dynamics and phrasing suggested here: "${instruction}"`
    : `Perform a realistic vocal impression of a ${type} part.
       Genre: ${context.genre}. Key: ${context.key}. BPM: ${context.bpm}.
       Script: "${instruction}". 
       Focus on the bracketed dynamics like [ghost] or [accent]. 
       Perform only the sounds, no speaking.`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: performancePrompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voice },
        },
      },
    },
  });

  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData?.data) {
        return decodeBase64(part.inlineData.data);
      }
    }
  }

  throw new Error(`No audio data returned for ${type}`);
};

function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useEffect, useState } from 'react';
import { AudioTrack } from '../types';
import { STEM_CONFIG } from '../constants';
import { Link2 } from 'lucide-react';

interface MixerTrackProps {
  track: AudioTrack;
  allTracks: AudioTrack[];
  onUpdate: (id: string, updates: Partial<AudioTrack>) => void;
  isPlaying?: boolean;
}

const MixerTrack: React.FC<MixerTrackProps> = ({ track, allTracks, onUpdate, isPlaying }) => {
  const config = STEM_CONFIG[track.type];
  const [meterLevel, setMeterLevel] = useState(0);

  useEffect(() => {
    let interval: number;
    if (isPlaying && !track.isMuted) {
      interval = window.setInterval(() => {
        const base = track.volume * 70;
        const bounce = Math.random() * 20;
        setMeterLevel(Math.min(100, base + bounce));
      }, 80);
    } else {
      setMeterLevel(0);
    }
    return () => clearInterval(interval);
  }, [isPlaying, track.isMuted, track.volume]);

  const getPanLabel = (val: number) => {
    if (Math.abs(val) < 0.1) return 'C';
    return val < 0 ? `${Math.abs(Math.round(val * 100))}L` : `${Math.round(val * 100)}R`;
  };

  const handleEqChange = (band: 'low' | 'mid' | 'high', value: number) => {
    onUpdate(track.id, {
      eq: {
        ...track.eq,
        [band]: value
      }
    });
  };

  return (
    <div className="flex flex-col items-center bg-zinc-900/60 rounded-[2.5rem] p-5 w-32 border border-zinc-800/50 hover:border-zinc-700/50 transition-all shadow-2xl relative overflow-hidden group min-h-[550px]">
      <div 
        className="absolute top-0 left-0 right-0 h-1" 
        style={{ backgroundColor: track.color }} 
      />

      <div className="flex flex-col items-center gap-2 mb-4 mt-2">
        <div 
          className="w-10 h-10 rounded-2xl flex items-center justify-center shadow-lg border border-white/5 transition-transform group-hover:scale-110"
          style={{ backgroundColor: `${track.color}15`, color: track.color, boxShadow: `0 0 20px ${track.color}10` }}
        >
          {config.icon}
        </div>
        <span className="text-[9px] font-black text-zinc-400 truncate w-full text-center uppercase tracking-widest px-1">
          {track.name}
        </span>
      </div>

      <div className="grid grid-cols-2 gap-1.5 w-full mb-4">
        <button 
          onClick={() => onUpdate(track.id, { isMuted: !track.isMuted })}
          className={`py-1.5 rounded-lg text-[7px] font-black uppercase tracking-widest transition-all border ${
            track.isMuted 
              ? 'bg-red-600 border-red-500 text-white shadow-lg' 
              : 'bg-zinc-800 border-zinc-700 text-zinc-500 hover:text-zinc-300'
          }`}
        >
          Mute
        </button>
        <button 
          onClick={() => onUpdate(track.id, { isSolo: !track.isSolo })}
          className={`py-1.5 rounded-lg text-[7px] font-black uppercase tracking-widest transition-all border ${
            track.isSolo 
              ? 'bg-yellow-500 border-yellow-400 text-zinc-900 shadow-lg' 
              : 'bg-zinc-800 border-zinc-700 text-zinc-500 hover:text-zinc-300'
          }`}
        >
          Solo
        </button>
      </div>

      {/* Sidechain Section */}
      <div className="w-full mb-4 px-1">
        <div className="flex items-center gap-1.5 mb-1.5">
          <Link2 size={10} className="text-zinc-600" />
          <span className="text-[7px] font-black text-zinc-600 uppercase tracking-widest">Sidechain</span>
        </div>
        <select 
          value={track.sidechainSourceId || ''}
          onChange={(e) => onUpdate(track.id, { sidechainSourceId: e.target.value || undefined })}
          className="w-full bg-black/40 border border-zinc-800 rounded-lg p-1.5 text-[8px] font-bold text-zinc-400 outline-none hover:border-zinc-700 transition-all"
        >
          <option value="">None</option>
          {allTracks.filter(t => t.id !== track.id).map(t => (
            <option key={t.id} value={t.id}>{t.name}</option>
          ))}
        </select>
      </div>

      {/* 3-Band EQ Section */}
      <div className="w-full flex flex-col gap-3 mb-4 p-2 bg-black/20 rounded-2xl border border-zinc-800/50">
        <div className="flex flex-col gap-1">
           <div className="flex justify-between text-[6px] font-black text-zinc-600 uppercase tracking-widest">
             <span>HI</span>
             <span className={track.eq.high !== 0 ? 'text-pink-500' : ''}>{track.eq.high}dB</span>
           </div>
           <input 
             type="range" min="-12" max="12" step="0.5" value={track.eq.high} 
             onChange={(e) => handleEqChange('high', parseFloat(e.target.value))}
             className="w-full accent-pink-600 h-1 bg-zinc-800 rounded-full appearance-none cursor-pointer"
           />
        </div>
        <div className="flex flex-col gap-1">
           <div className="flex justify-between text-[6px] font-black text-zinc-600 uppercase tracking-widest">
             <span>MID</span>
             <span className={track.eq.mid !== 0 ? 'text-indigo-500' : ''}>{track.eq.mid}dB</span>
           </div>
           <input 
             type="range" min="-12" max="12" step="0.5" value={track.eq.mid} 
             onChange={(e) => handleEqChange('mid', parseFloat(e.target.value))}
             className="w-full accent-indigo-600 h-1 bg-zinc-800 rounded-full appearance-none cursor-pointer"
           />
        </div>
        <div className="flex flex-col gap-1">
           <div className="flex justify-between text-[6px] font-black text-zinc-600 uppercase tracking-widest">
             <span>LO</span>
             <span className={track.eq.low !== 0 ? 'text-emerald-500' : ''}>{track.eq.low}dB</span>
           </div>
           <input 
             type="range" min="-12" max="12" step="0.5" value={track.eq.low} 
             onChange={(e) => handleEqChange('low', parseFloat(e.target.value))}
             className="w-full accent-emerald-600 h-1 bg-zinc-800 rounded-full appearance-none cursor-pointer"
           />
        </div>
      </div>

      <div className="w-full mb-6 flex flex-col items-center gap-1.5">
        <div className="flex justify-between w-full px-1">
          <span className="text-[7px] font-black text-zinc-600">L</span>
          <span className="text-[8px] font-black text-pink-500/80 tracking-tighter mono">{getPanLabel(track.pan)}</span>
          <span className="text-[7px] font-black text-zinc-600">R</span>
        </div>
        <div className="relative w-full h-1.5 bg-zinc-800/80 rounded-full border border-zinc-700/30">
          <input 
            type="range"
            min="-1"
            max="1"
            step="0.01"
            value={track.pan}
            onChange={(e) => onUpdate(track.id, { pan: parseFloat(e.target.value) })}
            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
          />
          <div 
            className="absolute top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full border border-zinc-400 shadow-md pointer-events-none transition-transform"
            style={{ left: `calc(${(track.pan + 1) * 50}% - 6px)` }}
          />
        </div>
      </div>

      <div className="flex gap-4 h-44 w-full items-center justify-center">
        <div className="w-2.5 h-full bg-black/40 rounded-full border border-zinc-800/50 relative overflow-hidden flex flex-col justify-end p-[1px]">
          <div 
            className="w-full transition-all duration-75 rounded-full"
            style={{ 
              height: `${meterLevel}%`,
              background: meterLevel > 85 
                ? 'linear-gradient(to top, #10b981, #f59e0b, #ef4444)' 
                : meterLevel > 60 
                  ? 'linear-gradient(to top, #10b981, #f59e0b)' 
                  : '#10b981',
            }}
          />
        </div>

        <div className="relative h-full w-8 flex flex-col items-center">
          <div className="absolute inset-y-0 w-1 bg-zinc-800 rounded-full shadow-inner" />
          <input
            type="range"
            min="0"
            max="1.2"
            step="0.001"
            value={track.volume}
            onChange={(e) => onUpdate(track.id, { volume: parseFloat(e.target.value) })}
            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-20 -rotate-180 fader-vertical"
            style={{ direction: 'rtl' }}
          />
          <div 
            className="absolute w-7 h-10 bg-zinc-300 rounded-md border-y border-zinc-400 shadow-xl flex flex-col items-center justify-center pointer-events-none"
            style={{ 
              bottom: `calc(${Math.min(100, (track.volume / 1.2) * 100)}% - 20px)`,
            }}
          >
            <div className="w-full h-[2px] bg-zinc-800/20 mb-[2px]" />
            <div className="absolute left-0 right-0 h-[2px]" style={{ backgroundColor: track.color }} />
          </div>
        </div>
      </div>

      <style>{`
        .fader-vertical { appearance: slider-vertical; writing-mode: bt-lr; }
      `}</style>
    </div>
  );
};

