              >
                <Zap size={18} className="text-indigo-600" />
                {isGenerating ? 'Synthesizing...' : 'Generate New Band'}
              </button>
            </div>
          </div>
        )}

        {sidebarView === 'visuals' && (
          <div className="p-7 space-y-8 animate-in slide-in-from-right-4">
             <header>
                <h2 className="text-2xl font-black tracking-tight mb-1 uppercase italic">Visualizer</h2>
                <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.2em]">Veo 3.1 Fast Video Synth</p>
             </header>

             <div className="space-y-6">
                <div className="space-y-4">
                   <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Reference Image</label>
                   <div className="aspect-video bg-zinc-900 rounded-3xl border-2 border-dashed border-zinc-800 flex flex-col items-center justify-center overflow-hidden relative group">
                      {uploadedImage ? (
