                     <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Generated Output</label>
                     <video src={videoUrl} controls className="w-full rounded-2xl shadow-2xl border border-zinc-800" />
                  </div>
