        {sidebarView === 'library' && (
          <div className="p-7 space-y-6">
            <h2 className="text-2xl font-black tracking-tight uppercase italic">Session Library</h2>
            {library.length === 0 ? (
              <p className="text-zinc-600 text-[10px] font-black uppercase text-center py-10 tracking-[0.3em]">No saved sessions</p>
