                onClick={() => setActiveSong(song)}
                className={`w-full text-left p-4 rounded-2xl border transition-all flex items-center gap-4 group ${activeSong?.id === song.id ? 'bg-zinc-800/80 border-zinc-700' : 'bg-zinc-900/20 border-zinc-900 hover:border-zinc-800'}`}
              >
                <div className="w-10 h-10 bg-zinc-900 rounded-xl flex items-center justify-center group-hover:bg-zinc-800 border border-zinc-800">
                  <Music2 size={16} className="text-pink-500" />
                </div>
                <div className="flex-1 overflow-hidden">
                  <h4 className="font-black truncate text-sm tracking-tight">{song.title}</h4>
                  <div className="text-[9px] text-zinc-600 font-black uppercase tracking-widest italic">{song.genre} • {song.key}</div>
                </div>
              </button>
            ))}
          </div>
        )}
      </aside>

      <main className="flex-1 flex flex-col bg-[#020202]">
        {activeSong ? (
          <div className="flex-1 flex flex-col overflow-hidden">
            <div className="h-20 border-b border-zinc-900 flex items-center px-10 justify-between bg-zinc-950/40 backdrop-blur-2xl">
              <div className="flex items-center gap-8">
                <button 
                  onClick={isPlaying ? stopAll : () => playAll(tracks)}
                  className={`flex items-center gap-4 px-10 py-3.5 rounded-full font-black text-xs uppercase tracking-[0.3em] transition-all active:scale-95 shadow-2xl ${isPlaying ? 'bg-white text-black' : 'bg-indigo-600 text-white shadow-indigo-600/30 hover:bg-indigo-500'}`}
                >
                  {isPlaying ? <Square size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" />}
                  {isPlaying ? 'Stop Session' : 'Start Playback'}
                </button>

                <div className="flex items-center gap-8 bg-zinc-900/30 px-8 py-3 rounded-2xl border border-zinc-800/50 shadow-inner">
                   <div className="flex flex-col">
                     <span className="text-[8px] font-black uppercase text-zinc-600 tracking-widest mb-1 text-center">Tempo</span>
                     <span className="text-pink-500 font-black mono text-sm leading-none">{activeSong.bpm}</span>
                   </div>
                   <div className="w-px h-6 bg-zinc-800" />
                   <div className="flex flex-col">
                     <span className="text-[8px] font-black uppercase text-zinc-600 tracking-widest mb-1 text-center">Scale</span>
                     <span className="text-white font-black text-sm leading-none">{activeSong.key}</span>
                   </div>
                   <div className="w-px h-6 bg-zinc-800" />
                   <div className="flex items-center gap-3">
                      <Sparkles size={16} className="text-emerald-500" />
                      <span className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Master Saturation Live</span>
                   </div>
                </div>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-10 custom-scrollbar bg-[radial-gradient(circle_at_top,_#0a0a1a,_transparent)]">
              <div className="mb-12">
                <h1 className="text-7xl font-black tracking-tighter mb-4 italic bg-clip-text text-transparent bg-gradient-to-r from-white via-zinc-400 to-zinc-700">{activeSong.title}</h1>
                <p className="text-zinc-600 font-black uppercase tracking-[0.8em] text-[10px] ml-1">High-Fidelity Multi-Track Logic • Pro Dynamic Simulation</p>
              </div>

              <div className="grid grid-cols-1 gap-6">
                {tracks.map(track => (
                  <div key={track.id} className="flex gap-8 items-center bg-zinc-950/40 p-3 pr-10 rounded-[2.5rem] border border-zinc-900/80 hover:border-zinc-700 transition-all group relative overflow-hidden">
                    <div className="w-56 p-5 flex flex-col gap-4 z-10 border-r border-zinc-900/50">
                      <div className="flex items-center gap-4">
                        <div className="w-4 h-4 rounded-full shadow-[0_0_15px_currentColor]" style={{ color: track.color, backgroundColor: 'currentColor' }} />
                        <span className="font-black uppercase tracking-[0.2em] text-[11px] text-zinc-300 truncate">{track.name}</span>
                      </div>
                      <div className="flex gap-2">
                        <button onClick={() => handleUpdateTrack(track.id, { isMuted: !track.isMuted })} className={`text-[10px] font-black px-4 py-2 rounded-xl border transition-all ${track.isMuted ? 'bg-red-600 border-red-500 text-white' : 'bg-zinc-900/60 border-zinc-800 text-zinc-500 hover:text-zinc-300'}`}>MUTE</button>
                        <button onClick={() => handleUpdateTrack(track.id, { isSolo: !track.isSolo })} className={`text-[10px] font-black px-4 py-2 rounded-xl border transition-all ${track.isSolo ? 'bg-yellow-500 border-yellow-400 text-zinc-950' : 'bg-zinc-900/60 border-zinc-800 text-zinc-500 hover:text-zinc-300'}`}>SOLO</button>
                      </div>
                    </div>

                    <div className="flex-1 h-24 bg-black/60 rounded-[2rem] border border-zinc-900/50 overflow-hidden relative shadow-inner">
                       <Waveform color={track.color} intensity={track.buffer ? 1 : 0.1} isPlaying={isPlaying && !track.isMuted} height={96} />
                       <div className="absolute top-2 right-6 text-[8px] font-black text-zinc-800 tracking-[0.4em] uppercase flex items-center gap-2">
                          PCM STREAM RAW_2.5
                          {track.sidechainSourceId && <span className="text-indigo-400 flex items-center gap-1"><Link2 size={8}/> DUCKING</span>}
                       </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="h-96 border-t border-zinc-900 bg-[#050505]/95 backdrop-blur-3xl p-10 flex gap-8 overflow-x-auto custom-scrollbar items-end shadow-2xl relative">
               <div className="absolute top-4 left-1/2 -translate-x-1/2 text-[10px] font-black text-zinc-800 tracking-[1em] uppercase pointer-events-none">Virtual Mixing Console v2.5</div>
               {tracks.map(track => (
                 <MixerTrack key={track.id} track={track} allTracks={tracks} onUpdate={handleUpdateTrack} isPlaying={isPlaying} />
               ))}
               <div className="flex flex-col items-center bg-zinc-900/40 rounded-[2rem] p-8 w-40 border-2 border-zinc-800/50 ml-auto h-full justify-between shadow-2xl relative">
                <Volume2 size={24} className="text-zinc-600 mt-4" />
                <div className="flex-1 w-full flex justify-center py-8 relative">
