          background: #eee; 
          border-radius: 4px; 
          cursor: pointer; 
          border: 1px solid #999;
          box-shadow: 0 4px 10px rgba(0,0,0,0.5);
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { 
  Play, 
  Square, 
  Settings2, 
  Music2, 
  Volume2, 
  Disc, 
  Library, 
  Home, 
  Sparkles, 
  Zap, 
  Mic2,
  AlertCircle,
  Mic,
  Lightbulb,
  Search,
  Video,
  Upload,
  ExternalLink,
  Loader2,
  // Fix: Add missing Link2 import
  Link2
} from 'lucide-react';
import { 
  generateSongStructure, 
  synthesizeStemAudio, 
  decodeAudioData, 
  transcribeAudio, 
  getQuickSuggestions,
  searchMusicTrends,
  generateMusicVideo
} from './services/geminiService';
import { SongStructure, AudioTrack, StemType, GenerationParams, SearchResult } from './types';
import { STEM_CONFIG } from './constants';
import Waveform from './components/Waveform';
import MixerTrack from './components/MixerTrack';

const App: React.FC = () => {
  const [params, setParams] = useState<GenerationParams>({
    lyrics: '',
    style: '',
    key: 'C',
    scale: 'Major',
    vocalGender: 'Female',
    vocalStyle: 'Powerful',
    instruments: ['Drums', 'Bass', 'Vocals', 'Synths', 'Pads']
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [isSearching, setIsSearching] = useState(false);
  const [isGeneratingVideo, setIsGeneratingVideo] = useState(false);
  const [searchResults, setSearchResults] = useState<SearchResult | null>(null);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [generationStep, setGenerationStep] = useState<string>('');
  const [activeSong, setActiveSong] = useState<SongStructure | null>(null);
  const [library, setLibrary] = useState<SongStructure[]>([]);
  const [tracks, setTracks] = useState<AudioTrack[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [sidebarView, setSidebarView] = useState<'create' | 'library' | 'visuals'>('create');

  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  const audioCtxRef = useRef<AudioContext | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const sourceNodesRef = useRef<Map<string, AudioBufferSourceNode>>(new Map());
  const gainNodesRef = useRef<Map<string, GainNode>>(new Map());
  const panNodesRef = useRef<Map<string, PannerNode>>(new Map());
  const analysersRef = useRef<Map<string, AnalyserNode>>(new Map());
  const eqNodesRef = useRef<Map<string, { low: BiquadFilterNode, mid: BiquadFilterNode, high: BiquadFilterNode }>>(new Map());
  const masterCompressorRef = useRef<DynamicsCompressorNode | null>(null);

  const sidechainAnimFrameRef = useRef<number | null>(null);

  const initAudio = () => {
    if (!audioCtxRef.current) {
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioCtxRef.current = ctx;

      const compressor = ctx.createDynamicsCompressor();
      compressor.threshold.setValueAtTime(-24, ctx.currentTime);
      compressor.knee.setValueAtTime(30, ctx.currentTime);
      compressor.ratio.setValueAtTime(12, ctx.currentTime);
      compressor.attack.setValueAtTime(0.003, ctx.currentTime);
      compressor.release.setValueAtTime(0.25, ctx.currentTime);
      masterCompressorRef.current = compressor;
      compressor.connect(ctx.destination);
    }
  };

  /**
   * Sidechain Loop
   * Responsive ducking using envelope followers
   */
  useEffect(() => {
    const processSidechain = () => {
      tracks.forEach(track => {
        if (track.sidechainSourceId) {
          const triggerAnalyser = analysersRef.current.get(track.sidechainSourceId);
          const targetGain = gainNodesRef.current.get(track.id);

          if (triggerAnalyser && targetGain) {
            const bufferLength = triggerAnalyser.frequencyBinCount;
            const dataArray = new Uint8Array(bufferLength);
            triggerAnalyser.getByteTimeDomainData(dataArray);

            // Calculate RMS level
            let sumSquares = 0;
            for (let i = 0; i < bufferLength; i++) {
              const dev = (dataArray[i] - 128) / 128;
              sumSquares += dev * dev;
            }
            const rms = Math.sqrt(sumSquares / bufferLength);

            // Ducking logic: Reduce gain as trigger volume increases
            const duckingAmount = 0.8; // How much it ducks (0 to 1)
            const envValue = 1 - (rms * duckingAmount * 3);
            const clampedEnv = Math.max(0.2, Math.min(1, envValue));

            const baseVol = track.volume;
            targetGain.gain.setTargetAtTime(baseVol * clampedEnv, audioCtxRef.current!.currentTime, 0.05);
          }
        }
      });
      sidechainAnimFrameRef.current = requestAnimationFrame(processSidechain);
    };

    if (isPlaying) {
      sidechainAnimFrameRef.current = requestAnimationFrame(processSidechain);
    } else {
      if (sidechainAnimFrameRef.current) cancelAnimationFrame(sidechainAnimFrameRef.current);
    }

    return () => {
      if (sidechainAnimFrameRef.current) cancelAnimationFrame(sidechainAnimFrameRef.current);
    };
  }, [isPlaying, tracks]);

  const handleTranscribe = async () => {
    try {
      setIsTranscribing(true);
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      const chunks: Blob[] = [];

      mediaRecorder.ondataavailable = (e) => chunks.push(e.data);
      mediaRecorder.onstop = async () => {
        const blob = new Blob(chunks, { type: 'audio/wav' });
        const reader = new FileReader();
        reader.readAsDataURL(blob);
        reader.onloadend = async () => {
          const base64 = (reader.result as string).split(',')[1];
          const text = await transcribeAudio(base64);
          setParams(prev => ({ ...prev, lyrics: prev.lyrics + " " + text }));
          setIsTranscribing(false);
          stream.getTracks().forEach(t => t.stop());
        };
      };

      mediaRecorder.start();
      setTimeout(() => mediaRecorder.stop(), 5000);
    } catch (err) {
      console.error(err);
      setIsTranscribing(false);
      setError("Microphone access denied.");
    }
  };

  const handleSearchTrends = async () => {
    if (!params.style && !params.lyrics) return;
    setIsSearching(true);
    setSearchResults(null);
    try {
      const res = await searchMusicTrends(params.style || params.lyrics);
      setSearchResults(res);
    } catch (e) {
      console.error(e);
      setError("Search failed. Try again later.");
    } finally {
      setIsSearching(false);
    }
  };

  const handleQuickSuggest = async () => {
    if (!params.lyrics) return;
    setIsSuggesting(true);
    try {
      const styles = await getQuickSuggestions(params.lyrics);
      setSuggestions(styles);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSuggesting(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleGenerateVideo = async () => {
    if (!uploadedImage || !activeSong) return;

    // Check for API key if using Veo
    if (!(window as any).aistudio?.hasSelectedApiKey()) {
      await (window as any).aistudio?.openSelectKey();
      return;
    }

    setIsGeneratingVideo(true);
    try {
      const base64 = uploadedImage.split(',')[1];
      const url = await generateMusicVideo({
        imageBytes: base64,
        prompt: `Cinematic music video visuals for a ${activeSong.genre} track titled ${activeSong.title}. Ethereal, moody atmosphere.`,
        ratio: '16:9'
      });
      setVideoUrl(url);
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes("Requested entity was not found")) {
        await (window as any).aistudio?.openSelectKey();
      }
      setError("Video generation failed.");
    } finally {
      setIsGeneratingVideo(false);
    }
  };

  const stopAll = useCallback(() => {
    setIsPlaying(false);
    sourceNodesRef.current.forEach(node => {
      try { node.stop(); } catch(e) {}
    });
    sourceNodesRef.current.clear();
  }, []);

  const playAll = useCallback(async (currentTracks: AudioTrack[]) => {
    initAudio();
    if (!audioCtxRef.current || currentTracks.length === 0) return;
    if (audioCtxRef.current.state === 'suspended') await audioCtxRef.current.resume();

    stopAll();
    const ctx = audioCtxRef.current!;
    const globalStartTime = ctx.currentTime + 0.1;
    setIsPlaying(true);

    const anySolo = currentTracks.some(t => t.isSolo);

    currentTracks.forEach(track => {
      if (track.buffer && masterCompressorRef.current) {
        const source = ctx.createBufferSource();
        source.buffer = track.buffer;

        // Setup Analyser for metering/sidechain
        let analyser = analysersRef.current.get(track.id);
        if (!analyser) {
          analyser = ctx.createAnalyser();
          analyser.fftSize = 256;
          analysersRef.current.set(track.id, analyser);
        }

        // Setup EQ
        let eq = eqNodesRef.current.get(track.id);
        if (!eq) {
          const low = ctx.createBiquadFilter();
          low.type = 'lowshelf';
          low.frequency.value = 100;
          const mid = ctx.createBiquadFilter();
          mid.type = 'peaking';
          mid.frequency.value = 1000;
          mid.Q.value = 1;
          const high = ctx.createBiquadFilter();
          high.type = 'highshelf';
          high.frequency.value = 10000;
          eq = { low, mid, high };
          eqNodesRef.current.set(track.id, eq);
        }

        eq.low.gain.setValueAtTime(track.eq.low, ctx.currentTime);
        eq.mid.gain.setValueAtTime(track.eq.mid, ctx.currentTime);
        eq.high.gain.setValueAtTime(track.eq.high, ctx.currentTime);

        let gainNode = gainNodesRef.current.get(track.id);
        if (!gainNode) {
          gainNode = ctx.createGain();
          gainNodesRef.current.set(track.id, gainNode);
        }

        const targetGain = track.isMuted ? 0 : (anySolo && !track.isSolo ? 0 : track.volume);
        gainNode.gain.setValueAtTime(targetGain, ctx.currentTime);

        let panNode = panNodesRef.current.get(track.id);
        if (!panNode) {
          panNode = ctx.createPanner();
          panNode.panningModel = 'equalpower';
          panNodesRef.current.set(track.id, panNode);
        }
        panNode.positionX.setValueAtTime(track.pan, ctx.currentTime);

        // Chain: source -> eq chain -> analyser -> pan -> gain -> master
        source.connect(eq.low);
        eq.low.connect(eq.mid);
        eq.mid.connect(eq.high);
        eq.high.connect(analyser);
        analyser.connect(panNode);
        panNode.connect(gainNode);
        gainNode.connect(masterCompressorRef.current);

        source.loop = true;
        source.start(globalStartTime);
        sourceNodesRef.current.set(track.id, source);
      }
    });
  }, [stopAll]);

  const handleUpdateTrack = (id: string, updates: Partial<AudioTrack>) => {
    setTracks(prev => {
      const nextTracks = prev.map(t => t.id === id ? { ...t, ...updates } : t);
      const anySolo = nextTracks.some(t => t.isSolo);
      const track = nextTracks.find(t => t.id === id);

      if (track) {
        const ctx = audioCtxRef.current;
        const now = ctx?.currentTime || 0;
        const gain = gainNodesRef.current.get(track.id);
        if (gain) {
          const targetGain = track.isMuted ? 0 : (anySolo && !track.isSolo ? 0 : track.volume);
          gain.gain.setTargetAtTime(targetGain, now, 0.05);
        }
        const pan = panNodesRef.current.get(track.id);
        if (pan) pan.positionX.setTargetAtTime(track.pan, now, 0.08);
        if (updates.eq) {
          const eqNodes = eqNodesRef.current.get(track.id);
          if (eqNodes) {
            eqNodes.low.gain.setTargetAtTime(track.eq.low, now, 0.1);
            eqNodes.mid.gain.setTargetAtTime(track.eq.mid, now, 0.1);
            eqNodes.high.gain.setTargetAtTime(track.eq.high, now, 0.1);
          }
        }
      }
      return nextTracks;
    });
  };

  const handleGenerate = async () => {
    if (!params.style || !params.lyrics) {
      setError("Please provide lyrics and a style.");
      return;
    }
    initAudio();
    setIsGenerating(true);
    setError(null);
    stopAll();

    try {
      setGenerationStep('Architecting Arrangement...');
      const structure = await generateSongStructure(params);

      const tracksToBuild: AudioTrack[] = [];

      for (const [index, stem] of structure.stems.entries()) {
        setGenerationStep(`Rendering ${stem.type}...`);
        try {
          const instruction = stem.type === StemType.VOCALS 
            ? structure.lyrics.chorus 
            : stem.performance_instruction;

          const audioBytes = await synthesizeStemAudio(instruction, stem.type as StemType, {
            genre: structure.genre,
            bpm: structure.bpm,
            key: structure.key,
            vocalStyle: params.vocalStyle
          });

          const buffer = await decodeAudioData(audioBytes, audioCtxRef.current!);

          let defaultPan = 0;
          if (stem.type === StemType.SYNTH) defaultPan = -0.5;
          if (stem.type === StemType.PADS) defaultPan = 0.5;

          tracksToBuild.push({
            id: `stem-${index}-${Date.now()}`,
            name: stem.type,
            type: stem.type as StemType,
            buffer: buffer,
            volume: stem.type === StemType.VOCALS ? 0.9 : 0.6,
            pan: defaultPan,
            isMuted: false,
            isSolo: false,
            color: STEM_CONFIG[stem.type as StemType].color,
            eq: { low: 0, mid: 0, high: 0 }
          });
        } catch (stemError) {
          console.warn(`Failed to synthesize stem: ${stem.type}`, stemError);
        }
      }

      setTracks(tracksToBuild);
      setActiveSong(structure);
      setLibrary(prev => [structure, ...prev]);
      playAll(tracksToBuild);

    } catch (err: any) {
      setError(err.message || "An error occurred.");
    } finally {
      setIsGenerating(false);
      setGenerationStep('');
    }
  };

  const KEYS = ['C', 'C#', 'D', 'Eb', 'E', 'F', 'F#', 'G', 'Ab', 'A', 'Bb', 'B'];

  return (
    <div className="flex h-screen bg-[#020202] text-zinc-100 font-sans selection:bg-pink-500/30">
      <nav className="w-16 border-r border-zinc-900 flex flex-col items-center py-6 gap-8 bg-zinc-950/50 backdrop-blur-md">
        <div className="w-10 h-10 bg-gradient-to-tr from-pink-600 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-pink-600/20">
          <Disc className="text-white animate-spin-slow" size={20} />
        </div>
        <div className="flex flex-col gap-6">
          <button onClick={() => setSidebarView('create')} className={`p-2.5 rounded-xl transition-all ${sidebarView === 'create' ? 'bg-zinc-800 text-white' : 'text-zinc-600 hover:text-zinc-300'}`}>
            <Home size={22} />
          </button>
          <button onClick={() => setSidebarView('library')} className={`p-2.5 rounded-xl transition-all ${sidebarView === 'library' ? 'bg-zinc-800 text-white' : 'text-zinc-600 hover:text-zinc-300'}`}>
            <Library size={22} />
          </button>
          <button onClick={() => setSidebarView('visuals')} className={`p-2.5 rounded-xl transition-all ${sidebarView === 'visuals' ? 'bg-zinc-800 text-white' : 'text-zinc-600 hover:text-zinc-300'}`}>
            <Video size={22} />
          </button>
        </div>
      </nav>

      <aside className="w-[400px] border-r border-zinc-900 bg-[#050505] flex flex-col overflow-y-auto custom-scrollbar shadow-2xl">
        {sidebarView === 'create' && (
          <div className="p-7 space-y-8">
            <header className="flex justify-between items-start">
              <div>
                <h2 className="text-2xl font-black tracking-tight mb-1 uppercase italic">Aether Studio</h2>
                <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.2em]">Nuanced AI Orchestration</p>
              </div>
              <div className="flex gap-2">
                <button 
                  onClick={handleQuickSuggest} 
                  disabled={isSuggesting || !params.lyrics}
                  className="p-2 bg-indigo-600/20 text-indigo-400 rounded-xl hover:bg-indigo-600/30 transition-all disabled:opacity-30"
                  title="Smart Suggestions"
                >
                  <Lightbulb size={20} className={isSuggesting ? "animate-pulse" : ""} />
                </button>
                <button 
                  onClick={handleSearchTrends} 
                  disabled={isSearching || (!params.style && !params.lyrics)}
                  className="p-2 bg-emerald-600/20 text-emerald-400 rounded-xl hover:bg-emerald-600/30 transition-all disabled:opacity-30"
                  title="Search Music Trends"
                >
                  <Search size={20} className={isSearching ? "animate-spin" : ""} />
                </button>
              </div>
            </header>

            <div className="space-y-6">
              <div className="space-y-2.5 relative">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Lyrics & Mood</label>
                <textarea 
                  value={params.lyrics}
                  onChange={(e) => setParams({...params, lyrics: e.target.value})}
                  placeholder="Type or speak your ideas..."
                  className="w-full h-28 bg-zinc-900/30 border border-zinc-800/80 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-pink-500/30 outline-none resize-none"
                />
                <button 
                  onClick={handleTranscribe}
                  className={`absolute bottom-3 right-3 p-2 rounded-full transition-all ${isTranscribing ? 'bg-red-600 text-white animate-pulse' : 'bg-zinc-800 text-zinc-400 hover:text-white'}`}
                >
                  <Mic size={16} />
                </button>
              </div>

              {searchResults && (
                <div className="p-4 bg-zinc-900/40 border border-emerald-500/20 rounded-2xl animate-in zoom-in-95">
                  <h4 className="text-[10px] font-black uppercase tracking-widest text-emerald-400 mb-2 flex items-center gap-2">
                    <Search size={12} /> Trend Intelligence
                  </h4>
                  <p className="text-[11px] text-zinc-300 leading-relaxed mb-3 italic">"{searchResults.text}"</p>
                  <div className="flex flex-col gap-1.5">
                    {searchResults.sources.slice(0, 2).map((s, i) => (
                      <a key={i} href={s.uri} target="_blank" className="flex items-center gap-2 text-[8px] font-black text-zinc-500 hover:text-white uppercase tracking-widest group">
                        <ExternalLink size={10} className="group-hover:text-emerald-500" /> {s.title}
                      </a>
                    ))}
                  </div>
                </div>
              )}

              {suggestions.length > 0 && (
                <div className="flex flex-wrap gap-2 animate-in fade-in slide-in-from-top-2">
                  {suggestions.map(s => (
                    <button 
                      key={s} 
                      onClick={() => setParams({...params, style: s})}
                      className="px-3 py-1 bg-indigo-500/10 border border-indigo-500/30 rounded-full text-[9px] font-black uppercase tracking-widest text-indigo-300 hover:bg-indigo-500/20 transition-all"
                    >
                      {s}
                    </button>
                  ))}
                </div>
              )}

              <div className="space-y-2.5">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Musical Genre</label>
                <input 
                  value={params.style}
                  onChange={(e) => setParams({...params, style: e.target.value})}
                  placeholder="e.g. Dreamy Lo-fi, Cinematic Orchestral"
                  className="w-full bg-zinc-900/30 border border-zinc-800/80 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-pink-500/30 outline-none"
                />
              </div>

              <div className="space-y-2.5">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Musical Key</label>
                <div className="grid grid-cols-6 gap-1">
                  {KEYS.map(k => (
                    <button 
                      key={k}
                      onClick={() => setParams({...params, key: k})}
                      className={`py-2 rounded-lg text-[10px] font-black transition-all border ${params.key === k ? 'bg-pink-600 border-pink-500 text-white shadow-lg shadow-pink-500/20' : 'bg-zinc-900/40 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
                    >
                      {k}
                    </button>
                  ))}
                </div>
                <div className="grid grid-cols-2 gap-2 mt-2">
                  {['Major', 'Minor'].map(s => (
                    <button 
                      key={s}
                      onClick={() => setParams({...params, scale: s as any})}
                      className={`py-2 rounded-xl text-[9px] font-black uppercase tracking-[0.2em] transition-all border ${params.scale === s ? 'bg-zinc-200 text-zinc-900' : 'bg-zinc-900/40 border-zinc-800 text-zinc-500'}`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>

              <button 
                onClick={handleGenerate}
                disabled={isGenerating}
                className="group relative w-full bg-white text-black py-5 rounded-2xl font-black uppercase tracking-[0.2em] text-xs hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-3 mt-4 disabled:opacity-40"
              >
                <Zap size={18} className="text-indigo-600" />
                {isGenerating ? 'Synthesizing...' : 'Generate New Band'}
              </button>
            </div>
          </div>
        )}

        {sidebarView === 'visuals' && (
          <div className="p-7 space-y-8 animate-in slide-in-from-right-4">
             <header>
                <h2 className="text-2xl font-black tracking-tight mb-1 uppercase italic">Visualizer</h2>
                <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.2em]">Veo 3.1 Fast Video Synth</p>
             </header>

