    4. For DRUMS: Use complex onomatopoeia like "ts-ts-BOOM [ghost] tchi-KACK".
    5. For BASS: Use deep, sliding vocalizations like "dooooom [slide] da-dum [vibrato]".

    Return valid JSON.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          genre: { type: Type.STRING },
          lyrics: {
            type: Type.OBJECT,
            properties: {
              verse: { type: Type.STRING },
              chorus: { type: Type.STRING },
              bridge: { type: Type.STRING }
            },
            required: ['verse', 'chorus', 'bridge']
          },
          stems: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, enum: Object.values(StemType) },
                description: { type: Type.STRING },
                performance_instruction: { type: Type.STRING },
                intensity: { type: Type.NUMBER }
              },
              required: ['type', 'description', 'performance_instruction', 'intensity']
            }
          }
        },
        required: ['title', 'bpm', 'key', 'genre', 'lyrics', 'stems']
      }
    }
  });

  if (!response.text) throw new Error("No structure generated.");
  const parsed = JSON.parse(response.text);

  return {
    ...parsed,
    id: crypto.randomUUID(),
    vocalGender: params.vocalGender as any,
    createdAt: Date.now()
  };
};

export const synthesizeStemAudio = async (
  instruction: string, 
  type: StemType, 
  context: { genre: string, bpm: number, key: string, vocalStyle?: string }
): Promise<Uint8Array> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const voice = type === StemType.BASS ? 'Fenrir' : type === StemType.VOCALS ? 'Kore' : 'Zephyr';

  let performancePrompt = "";

  if (type === StemType.VOCALS) {
    performancePrompt = `Sing these lyrics with a ${context.vocalStyle} performance in ${context.key} for a ${context.genre} track at ${context.bpm} BPM. 
       Incorporate natural breath work, emotional inflections, and specific phrasing dynamics: "${instruction}". Perform only the song, no speaking.`;
  } else if (type === StemType.BASS) {
    performancePrompt = `Perform a realistic vocal impression of a deep BASS guitar or synth bass. 
       Genre: ${context.genre}. Key: ${context.key}. BPM: ${context.bpm}.
       Focus on deep chest-resonant tones. Vary the slide articulation (smooth vs sudden) and vibrato intensity on sustained notes. 
       Emulate rhythmic plucking or slapping as indicated: "${instruction}". 
       Perform only the bass sounds, no speaking.`;
  } else if (type === StemType.SYNTH) {
    performancePrompt = `Perform a realistic vocal impression of an electronic SYNTH part. 
       Genre: ${context.genre}. Key: ${context.key}. BPM: ${context.bpm}.
       Incorporate modulation effects like resonant filter sweeps (e.g., 'wow-wow' or 'eee-aaa') or LFO-style volume/pitch fluctuations. 
       Focus on sharp envelopes or slow filter movements as scripted: "${instruction}". 
       Perform only the electronic sounds, no speaking.`;
  } else if (type === StemType.PADS) {
    performancePrompt = `Perform a realistic vocal impression of an atmospheric PADS part. 
       Genre: ${context.genre}. Key: ${context.key}. BPM: ${context.bpm}.
       Create airy, harmonic-rich swells that evolve. Focus on slow filter movements and ethereal textures. 
       Script: "${instruction}". 
       Perform only the pad textures, no speaking.`;
  } else if (type === StemType.DRUMS) {
    performancePrompt = `Perform a realistic percussive vocal impression of a DRUM kit. 
       Genre: ${context.genre}. BPM: ${context.bpm}.
       Provide sharp, punchy hits. Pay close attention to the contrast between heavy accents (kick/snare) and subtle ghost notes or hi-hat textures. 
       Emulate a natural room tone or reverb in your delivery. 
       Script: "${instruction}". 
       Perform only the drum sounds, no speaking.`;
  } else {
    performancePrompt = `Perform a realistic vocal impression of a ${type} part.
       Genre: ${context.genre}. Key: ${context.key}. BPM: ${context.bpm}.
       Script: "${instruction}".
       Focus on the bracketed dynamics like [ghost] or [accent].
       Perform only the musical sounds, no speaking.`;
  }

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: performancePrompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voice },
        },
      },
    },
  });

  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData?.data) {
        return decodeBase64(part.inlineData.data);
      }
    }
  }

  throw new Error(`No audio data returned for ${type}`);
};

function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export enum StemType {
  VOCALS = 'VOCALS',
  DRUMS = 'DRUMS',
  BASS = 'BASS',
  SYNTH = 'SYNTH',
  PADS = 'PADS',
  GUITAR = 'GUITAR',
  PIANO = 'PIANO'
}

export interface SongStructure {
  id: string;
  title: string;
  bpm: number;
  key: string;
  genre: string;
  lyrics: {
    verse: string;
    chorus: string;
    bridge: string;
  };
  stems: Array<{
    type: StemType;
    description: string;
    performance_instruction: string;
    intensity: number;
  }>;
  vocalGender: 'Male' | 'Female' | 'Non-binary';
  createdAt: number;
}

export interface AudioTrack {
  id: string;
  name: string;
  type: StemType;
  description?: string; // Detailed sonic description from the AI
  buffer?: AudioBuffer;
  volume: number;
  pan: number; // -1 to 1
  isMuted: boolean;
  isSolo: boolean;
  color: string;
  eq: {
    low: number;   // -12 to 12 dB
    mid: number;   // -12 to 12 dB
    high: number;  // -12 to 12 dB
  };
  sidechainSourceId?: string; // ID of the track that triggers ducking
}

export interface GenerationParams {
  lyrics: string;
  style: string;
  key: string;
  scale: 'Major' | 'Minor';
  vocalGender: string;
  vocalStyle: string;
  instruments: string[];
}

export interface SearchResult {
  text: string;
  sources: { title: string; uri: string }[];
}

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { 
  Play, 
  Square, 
  Settings2, 
