import { GoogleGenAI, Type, Modality } from "@google/genai";
import { SongStructure, StemType, GenerationParams, SearchResult } from "../types";

/**
 * Generates a short (2-3s) preview sample of a specific instrument type
 */
export const generateInstrumentSample = async (type: StemType, style: string): Promise<Uint8Array> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const voice = type === StemType.BASS ? 'Fenrir' : type === StemType.VOCALS ? 'Kore' : 'Zephyr';

  const prompt = `Perform a very short (2 second) signature sound for a ${type} part in the style of ${style || 'Modern Electronic'}. 
  Perform ONLY the sound. No speaking. ${type === StemType.VOCALS ? 'Sing a single melodic "Aah" or "Ooh".' : 'Create a single punchy signature hit or short riff.'}`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voice },
        },
      },
    },
  });

  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData?.data) {
        return decodeBase64(part.inlineData.data);
      }
    }
  }

  throw new Error(`Failed to sample ${type}`);
};

/**
 * Search Grounding for up-to-date music trends
 */
export const searchMusicTrends = async (query: string): Promise<SearchResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Research current music trends, production styles, and popular sonic palettes related to: "${query}". Provide a concise summary for a producer.`,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
    ?.map((chunk: any) => ({
      title: chunk.web?.title || 'Source',
      uri: chunk.web?.uri || ''
    }))
    .filter((s: any) => s.uri) || [];

  return {
    text: response.text || "No research data found.",
    sources
  };
};

/**
 * Veo Video Generation
 */
export const generateMusicVideo = async (imageParams: { imageBytes: string, prompt: string, ratio: '16:9' | '9:16' }) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: imageParams.prompt,
    image: {
      imageBytes: imageParams.imageBytes,
      mimeType: 'image/png',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: imageParams.ratio
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video generation failed.");

  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

/**
 * Fast AI responses for low-latency suggestions
 */
export const getQuickSuggestions = async (lyrics: string): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-lite-latest',
    contents: `Based on these lyrics: "${lyrics}", suggest 3 short musical styles or genres. Return only a comma-separated list.`,
  });
  return response.text?.split(',').map(s => s.trim()) || [];
};

/**
 * Audio transcription for voice input
 */
export const transcribeAudio = async (base64Audio: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'audio/wav',
            data: base64Audio
          }
        },
        { text: "Transcribe this musical idea or spoken lyric exactly. Only return the transcription." }
      ]
    }
  });
  return response.text || "";
};

export const generateSongStructure = async (params: GenerationParams): Promise<SongStructure> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    You are a world-class Music Producer. Create a song arrangement based on:
    - Concept: "${params.lyrics}"
    - Style: "${params.style}"
    - Key: ${params.key} ${params.scale}
    - Vocal Character: ${params.vocalGender}, Style: ${params.vocalStyle}

    Requirements for Performance Realism:
    1. Write 5 stems: VOCALS, DRUMS, BASS, SYNTH, PADS.
    2. Stems must have highly nuanced "performance_instruction" strings.
    3. Include dynamics (e.g., [ghost note], [heavy accent], [crescendo]) and timing variations (e.g., [laid back], [driving], [micro-delay]).
    4. For DRUMS: Use complex onomatopoeia like "ts-ts-BOOM [ghost] tchi-KACK".
    5. For BASS: Use deep, sliding vocalizations like "dooooom [slide] da-dum [vibrato]".

    Return valid JSON.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          genre: { type: Type.STRING },
          lyrics: {
            type: Type.OBJECT,
            properties: {
              verse: { type: Type.STRING },
              chorus: { type: Type.STRING },
              bridge: { type: Type.STRING }
            },
            required: ['verse', 'chorus', 'bridge']
          },
          stems: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                type: { type: Type.STRING, enum: Object.values(StemType) },
                description: { type: Type.STRING },
                performance_instruction: { type: Type.STRING },
                intensity: { type: Type.NUMBER }
              },
              required: ['type', 'description', 'performance_instruction', 'intensity']
            }
          }
        },
        required: ['title', 'bpm', 'key', 'genre', 'lyrics', 'stems']
      }
    }
  });

  if (!response.text) throw new Error("No structure generated.");
  const parsed = JSON.parse(response.text);

  return {
    ...parsed,
    id: crypto.randomUUID(),
    vocalGender: params.vocalGender as any,
    createdAt: Date.now()
  };
};

export const synthesizeStemAudio = async (
  instruction: string, 
  type: StemType, 
  context: { genre: string, bpm: number, key: string, vocalStyle?: string }
): Promise<Uint8Array> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const voice = type === StemType.BASS ? 'Fenrir' : type === StemType.VOCALS ? 'Kore' : 'Zephyr';

  let performancePrompt = "";

  if (type === StemType.VOCALS) {
    performancePrompt = `Sing these lyrics with a ${context.vocalStyle} performance in ${context.key} for a ${context.genre} track at ${context.bpm} BPM. 
       Incorporate natural breath work, emotional inflections, and specific phrasing dynamics: "${instruction}". Perform only the song, no speaking.`;
  } else if (type === StemType.BASS) {
    performancePrompt = `Perform a realistic vocal impression of a deep BASS guitar or synth bass. 
       Genre: ${context.genre}. Key: ${context.key}. BPM: ${context.bpm}.
       Focus on deep chest-resonant tones. Vary the slide articulation (smooth vs sudden) and vibrato intensity on sustained notes. 
       Emulate rhythmic plucking or slapping as indicated: "${instruction}". 
       Perform only the bass sounds, no speaking.`;
  } else if (type === StemType.SYNTH) {
    performancePrompt = `Perform a realistic vocal impression of an electronic SYNTH part. 
       Genre: ${context.genre}. Key: ${context.key}. BPM: ${context.bpm}.
       Incorporate modulation effects like resonant filter sweeps (e.g., 'wow-wow' or 'eee-aaa') or LFO-style volume/pitch fluctuations. 
       Focus on sharp envelopes or slow filter movements as scripted: "${instruction}". 
       Perform only the electronic sounds, no speaking.`;
  } else if (type === StemType.PADS) {
    performancePrompt = `Perform a realistic vocal impression of an atmospheric PADS part. 
       Genre: ${context.genre}. Key: ${context.key}. BPM: ${context.bpm}.
       Create airy, harmonic-rich swells that evolve. Focus on slow filter movements and ethereal textures. 
       Script: "${instruction}". 
       Perform only the pad textures, no speaking.`;
  } else if (type === StemType.DRUMS) {
    performancePrompt = `Perform a realistic percussive vocal impression of a DRUM kit. 
       Genre: ${context.genre}. BPM: ${context.bpm}.
       Provide sharp, punchy hits. Pay close attention to the contrast between heavy accents (kick/snare) and subtle ghost notes or hi-hat textures. 
       Emulate a natural room tone or reverb in your delivery. 
       Script: "${instruction}". 
       Perform only the drum sounds, no speaking.`;
  } else {
    performancePrompt = `Perform a realistic vocal impression of a ${type} part.
       Genre: ${context.genre}. Key: ${context.key}. BPM: ${context.bpm}.
       Script: "${instruction}".
       Focus on the bracketed dynamics like [ghost] or [accent].
       Perform only the musical sounds, no speaking.`;
  }

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: performancePrompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voice },
        },
      },
    },
  });

  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData?.data) {
        return decodeBase64(part.inlineData.data);
      }
    }
  }

  throw new Error(`No audio data returned for ${type}`);
};

function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { 
  Play, 
  Square, 
  Settings2, 
