              )}

              {suggestions.length > 0 && (
                <div className="flex flex-wrap gap-2 animate-in fade-in slide-in-from-top-2">
                  {suggestions.map(s => (
                    <button 
                      key={s} 
                      onClick={() => setParams({...params, style: s})}
                      className="px-3 py-1 bg-indigo-500/10 border border-indigo-500/30 rounded-full text-[9px] font-black uppercase tracking-widest text-indigo-300 hover:bg-indigo-500/20 transition-all"
