const App: React.FC = () => {
  const [params, setParams] = useState<GenerationParams>({
    lyrics: '',
    style: '',
    key: 'C',
    scale: 'Major',
    vocalGender: 'Female',
    vocalStyle: 'Powerful',
    instruments: ['Drums', 'Bass', 'Vocals', 'Synths', 'Pads']
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [isSearching, setIsSearching] = useState(false);
  const [isGeneratingVideo, setIsGeneratingVideo] = useState(false);
  const [previewingStem, setPreviewingStem] = useState<StemType | null>(null);
  const [searchResults, setSearchResults] = useState<SearchResult | null>(null);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [generationStep, setGenerationStep] = useState<string>('');
  const [activeSong, setActiveSong] = useState<SongStructure | null>(null);
  const [library, setLibrary] = useState<SongStructure[]>([]);
  const [tracks, setTracks] = useState<AudioTrack[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [sidebarView, setSidebarView] = useState<'create' | 'library' | 'visuals'>('create');
  const [masterGainValue, setMasterGainValue] = useState(0.8);

  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  const audioCtxRef = useRef<AudioContext | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const sourceNodesRef = useRef<Map<string, AudioBufferSourceNode>>(new Map());
  const gainNodesRef = useRef<Map<string, GainNode>>(new Map());
  const panNodesRef = useRef<Map<string, PannerNode>>(new Map());
  const analysersRef = useRef<Map<string, AnalyserNode>>(new Map());
  const eqNodesRef = useRef<Map<string, { low: BiquadFilterNode, mid: BiquadFilterNode, high: BiquadFilterNode }>>(new Map());
  const masterCompressorRef = useRef<DynamicsCompressorNode | null>(null);
  const masterGainNodeRef = useRef<GainNode | null>(null);

  const sidechainAnimFrameRef = useRef<number | null>(null);

  const initAudio = async () => {
    if (!audioCtxRef.current) {
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioCtxRef.current = ctx;

      const masterGain = ctx.createGain();
      masterGain.gain.setValueAtTime(masterGainValue, ctx.currentTime);
      masterGainNodeRef.current = masterGain;

      const compressor = ctx.createDynamicsCompressor();
      compressor.threshold.setValueAtTime(-24, ctx.currentTime);
      compressor.knee.setValueAtTime(30, ctx.currentTime);
      compressor.ratio.setValueAtTime(12, ctx.currentTime);
      compressor.attack.setValueAtTime(0.003, ctx.currentTime);
      compressor.release.setValueAtTime(0.25, ctx.currentTime);
      masterCompressorRef.current = compressor;

      compressor.connect(masterGain);
      masterGain.connect(ctx.destination);
    }

    if (audioCtxRef.current.state === 'suspended') {
      await audioCtxRef.current.resume();
    }
  };

  useEffect(() => {
    if (masterGainNodeRef.current && audioCtxRef.current) {
      masterGainNodeRef.current.gain.setTargetAtTime(masterGainValue, audioCtxRef.current.currentTime, 0.05);
    }
  }, [masterGainValue]);

  useEffect(() => {
    const processSidechain = () => {
      tracks.forEach(track => {
        if (track.sidechainSourceId) {
          const triggerAnalyser = analysersRef.current.get(track.sidechainSourceId);
          const targetGain = gainNodesRef.current.get(track.id);

          if (triggerAnalyser && targetGain) {
            const bufferLength = triggerAnalyser.frequencyBinCount;
            const dataArray = new Uint8Array(bufferLength);
            triggerAnalyser.getByteTimeDomainData(dataArray);

            let sumSquares = 0;
            for (let i = 0; i < bufferLength; i++) {
              const dev = (dataArray[i] - 128) / 128;
              sumSquares += dev * dev;
            }
            const rms = Math.sqrt(sumSquares / bufferLength);

            const duckingAmount = 0.8;
            const envValue = 1 - (rms * duckingAmount * 3);
            const clampedEnv = Math.max(0.2, Math.min(1, envValue));

            const baseVol = track.volume;
            targetGain.gain.setTargetAtTime(baseVol * clampedEnv, audioCtxRef.current!.currentTime, 0.05);
          }
        }
      });
      sidechainAnimFrameRef.current = requestAnimationFrame(processSidechain);
    };

    if (isPlaying) {
      sidechainAnimFrameRef.current = requestAnimationFrame(processSidechain);
    } else {
      if (sidechainAnimFrameRef.current) cancelAnimationFrame(sidechainAnimFrameRef.current);
    }

    return () => {
      if (sidechainAnimFrameRef.current) cancelAnimationFrame(sidechainAnimFrameRef.current);
    };
  }, [isPlaying, tracks]);

  const handlePreviewInstrument = async (type: StemType) => {
    if (previewingStem) return;
    await initAudio();
    setPreviewingStem(type);
    try {
      const audioBytes = await generateInstrumentSample(type, params.style);
      const buffer = await decodeAudioData(audioBytes, audioCtxRef.current!);
      const source = audioCtxRef.current!.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtxRef.current!.destination);
      source.start();
    } catch (e) {
      console.error(e);
      setError("Failed to generate instrument sample.");
    } finally {
      setPreviewingStem(null);
    }
  };

  const handleTranscribe = async () => {
    try {
      setIsTranscribing(true);
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      const chunks: Blob[] = [];

      mediaRecorder.ondataavailable = (e) => chunks.push(e.data);
      mediaRecorder.onstop = async () => {
        const blob = new Blob(chunks, { type: 'audio/wav' });
        const reader = new FileReader();
        reader.readAsDataURL(blob);
        reader.onloadend = async () => {
          const base64 = (reader.result as string).split(',')[1];
          const text = await transcribeAudio(base64);
          setParams(prev => ({ ...prev, lyrics: prev.lyrics + " " + text }));
          setIsTranscribing(false);
          stream.getTracks().forEach(t => t.stop());
        };
      };

      mediaRecorder.start();
      setTimeout(() => mediaRecorder.stop(), 5000);
    } catch (err) {
      console.error(err);
      setIsTranscribing(false);
      setError("Microphone access denied.");
    }
  };

  const handleSearchTrends = async () => {
    if (!params.style && !params.lyrics) return;
    setIsSearching(true);
    setSearchResults(null);
    try {
      const res = await searchMusicTrends(params.style || params.lyrics);
      setSearchResults(res);
    } catch (e) {
      console.error(e);
      setError("Search failed. Try again later.");
    } finally {
      setIsSearching(false);
    }
  };

  const handleQuickSuggest = async () => {
    if (!params.lyrics) return;
    setIsSuggesting(true);
    try {
      const styles = await getQuickSuggestions(params.lyrics);
      setSuggestions(styles);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSuggesting(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleGenerateVideo = async () => {
    if (!uploadedImage || !activeSong) return;

    if (!(window as any).aistudio?.hasSelectedApiKey()) {
      await (window as any).aistudio?.openSelectKey();
      return;
    }

    setIsGeneratingVideo(true);
    try {
      const base64 = uploadedImage.split(',')[1];
      const url = await generateMusicVideo({
        imageBytes: base64,
        prompt: `Cinematic music video visuals for a ${activeSong.genre} track titled ${activeSong.title}. Ethereal, moody atmosphere.`,
        ratio: '16:9'
      });
      setVideoUrl(url);
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes("Requested entity was not found")) {
        await (window as any).aistudio?.openSelectKey();
      }
      setError("Video generation failed.");
    } finally {
      setIsGeneratingVideo(false);
    }
  };

  const stopAll = useCallback(() => {
    setIsPlaying(false);
    sourceNodesRef.current.forEach(node => {
      try { node.stop(); } catch(e) {}
    });
    sourceNodesRef.current.clear();
  }, []);

  const playAll = useCallback(async (currentTracks: AudioTrack[]) => {
    await initAudio();
    if (!audioCtxRef.current || currentTracks.length === 0) return;

    stopAll();
    const ctx = audioCtxRef.current!;
    const globalStartTime = ctx.currentTime + 0.1;
    setIsPlaying(true);

    const anySolo = currentTracks.some(t => t.isSolo);

    currentTracks.forEach(track => {
      if (track.buffer && masterCompressorRef.current) {
        const source = ctx.createBufferSource();
        source.buffer = track.buffer;

        let analyser = analysersRef.current.get(track.id);
        if (!analyser) {
          analyser = ctx.createAnalyser();
          analyser.fftSize = 256;
          analysersRef.current.set(track.id, analyser);
        }

        let eq = eqNodesRef.current.get(track.id);
        if (!eq) {
          const low = ctx.createBiquadFilter();
          low.type = 'lowshelf';
          low.frequency.value = 100;
          const mid = ctx.createBiquadFilter();
          mid.type = 'peaking';
          mid.frequency.value = 1000;
          mid.Q.value = 1;
          const high = ctx.createBiquadFilter();
          high.type = 'highshelf';
          high.frequency.value = 10000;
          eq = { low, mid, high };
          eqNodesRef.current.set(track.id, eq);
        }

        eq.low.gain.setValueAtTime(track.eq.low, ctx.currentTime);
        eq.mid.gain.setValueAtTime(track.eq.mid, ctx.currentTime);
        eq.high.gain.setValueAtTime(track.eq.high, ctx.currentTime);

        let gainNode = gainNodesRef.current.get(track.id);
        if (!gainNode) {
          gainNode = ctx.createGain();
          gainNodesRef.current.set(track.id, gainNode);
        }

        const targetGain = track.isMuted ? 0 : (anySolo && !track.isSolo ? 0 : track.volume);
        gainNode.gain.setValueAtTime(targetGain, ctx.currentTime);

        let panNode = panNodesRef.current.get(track.id);
        if (!panNode) {
          panNode = ctx.createPanner();
          panNode.panningModel = 'equalpower';
          panNodesRef.current.set(track.id, panNode);
        }
        panNode.positionX.setValueAtTime(track.pan, ctx.currentTime);

        source.connect(eq.low);
        eq.low.connect(eq.mid);
        eq.mid.connect(eq.high);
        eq.high.connect(analyser);
        analyser.connect(panNode);
        panNode.connect(gainNode);
        gainNode.connect(masterCompressorRef.current);

        source.loop = true;
        source.start(globalStartTime);
        sourceNodesRef.current.set(track.id, source);
      }
    });
  }, [stopAll]);

  const handleUpdateTrack = (id: string, updates: Partial<AudioTrack>) => {
    setTracks(prev => {
      const nextTracks = prev.map(t => t.id === id ? { ...t, ...updates } : t);
      const anySolo = nextTracks.some(t => t.isSolo);
      const track = nextTracks.find(t => t.id === id);

      if (track) {
        const ctx = audioCtxRef.current;
        const now = ctx?.currentTime || 0;
        const gain = gainNodesRef.current.get(track.id);
        if (gain) {
          const targetGain = track.isMuted ? 0 : (anySolo && !track.isSolo ? 0 : track.volume);
          gain.gain.setTargetAtTime(targetGain, now, 0.05);
        }
        const pan = panNodesRef.current.get(track.id);
        if (pan) pan.positionX.setTargetAtTime(track.pan, now, 0.08);
        if (updates.eq) {
          const eqNodes = eqNodesRef.current.get(track.id);
          if (eqNodes) {
            eqNodes.low.gain.setTargetAtTime(track.eq.low, now, 0.1);
            eqNodes.mid.gain.setTargetAtTime(track.eq.mid, now, 0.1);
            eqNodes.high.gain.setTargetAtTime(track.eq.high, now, 0.1);
          }
        }
      }
      return nextTracks;
    });
  };

  const handleGenerate = async () => {
    if (!params.style || !params.lyrics) {
      setError("Please provide lyrics and a style.");
      return;
    }
    await initAudio();
    setIsGenerating(true);
    setError(null);
    stopAll();

    try {
      setGenerationStep('Architecting Arrangement...');
      const structure = await generateSongStructure(params);

      setGenerationStep(`Rendering 5 Stems in Parallel...`);

      // Generate all stems in parallel for better performance
      const stemPromises = structure.stems.map(async (stem, index) => {
        try {
          const instruction = stem.type === StemType.VOCALS 
            ? structure.lyrics.chorus 
            : stem.performance_instruction;

          const audioBytes = await synthesizeStemAudio(instruction, stem.type as StemType, {
            genre: structure.genre,
            bpm: structure.bpm,
            key: structure.key,
            vocalStyle: params.vocalStyle
          });

          const buffer = await decodeAudioData(audioBytes, audioCtxRef.current!);

          let defaultPan = 0;
          if (stem.type === StemType.SYNTH) defaultPan = -0.5;
          if (stem.type === StemType.PADS) defaultPan = 0.5;

          return {
            id: `stem-${index}-${Date.now()}`,
            name: stem.type,
            type: stem.type as StemType,
            description: stem.description,
            buffer: buffer,
            volume: stem.type === StemType.VOCALS ? 0.9 : 0.6,
            pan: defaultPan,
            isMuted: false,
            isSolo: false,
            color: STEM_CONFIG[stem.type as StemType].color,
            eq: { low: 0, mid: 0, high: 0 }
          } as AudioTrack;
        } catch (stemError) {
          console.warn(`Failed to synthesize stem: ${stem.type}`, stemError);
          return null;
        }
      });

      const results = await Promise.all(stemPromises);
      const tracksToBuild = results.filter((t): t is AudioTrack => t !== null);

      if (tracksToBuild.length === 0) {
        throw new Error("Failed to generate any audio stems.");
      }

      setTracks(tracksToBuild);
      setActiveSong(structure);
      setLibrary(prev => [structure, ...prev]);
      playAll(tracksToBuild);

    } catch (err: any) {
      console.error(err);
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsGenerating(false);
      setGenerationStep('');
    }
