                </button>
              </div>

              {searchResults && (
                <div className="p-4 bg-zinc-900/40 border border-emerald-500/20 rounded-2xl animate-in zoom-in-95">
                  <h4 className="text-[10px] font-black uppercase tracking-widest text-emerald-400 mb-2 flex items-center gap-2">
