              </div>

              <div className="space-y-2.5">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Musical Key</label>
                <div className="grid grid-cols-6 gap-1">
                  {KEYS.map(k => (
                    <button 
                      key={k}
                      onClick={() => setParams({...params, key: k})}
                      className={`py-2 rounded-lg text-[10px] font-black transition-all border ${params.key === k ? 'bg-pink-600 border-pink-500 text-white shadow-lg shadow-pink-500/20' : 'bg-zinc-900/40 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
                    >
                      {k}
                    </button>
                  ))}
                </div>
                <div className="grid grid-cols-2 gap-2 mt-2">
                  {['Major', 'Minor'].map(s => (
                    <button 
                      key={s}
                      onClick={() => setParams({...params, scale: s as any})}
                      className={`py-2 rounded-xl text-[9px] font-black uppercase tracking-[0.2em] transition-all border ${params.scale === s ? 'bg-zinc-200 text-zinc-900' : 'bg-zinc-900/40 border-zinc-800 text-zinc-500'}`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>

              <button 
                onClick={handleGenerate}
                disabled={isGenerating}
                className="group relative w-full bg-white text-black py-5 rounded-2xl font-black uppercase tracking-[0.2em] text-xs hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-3 mt-4 disabled:opacity-40"
              >
                <Zap size={18} className="text-indigo-600" />
                {isGenerating ? 'Synthesizing...' : 'Generate New Band'}
              </button>

              {error && (
                <div className="p-4 bg-red-500/10 border border-red-500/30 rounded-2xl flex items-center gap-3 text-red-400 text-[11px] font-bold animate-in fade-in zoom-in-95">
                  <AlertCircle size={16} />
                  {error}
                </div>
              )}
            </div>
          </div>
        )}

        {sidebarView === 'visuals' && (
          <div className="p-7 space-y-8 animate-in slide-in-from-right-4">
             <header>
                <h2 className="text-2xl font-black tracking-tight mb-1 uppercase italic">Visualizer</h2>
                <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.2em]">Veo 3.1 Fast Video Synth</p>
             </header>

             <div className="space-y-6">
                <div className="space-y-4">
                   <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Reference Image</label>
                   <div className="aspect-video bg-zinc-900 rounded-3xl border-2 border-dashed border-zinc-800 flex flex-col items-center justify-center overflow-hidden relative group">
                      {uploadedImage ? (
                        <>
                          <img src={uploadedImage} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" alt="Preview" />
                          <button onClick={() => setUploadedImage(null)} className="absolute top-4 right-4 bg-black/60 p-2 rounded-full text-white">
                            <Square size={16} fill="currentColor" />
                          </button>
                        </>
                      ) : (
                        <>
                          <Upload className="text-zinc-700 mb-2" size={32} />
                          <p className="text-[9px] font-black text-zinc-600 uppercase">Click to upload</p>
                          <input type="file" accept="image/*" onChange={handleImageUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
                        </>
                      )}
                   </div>
                </div>

                <button 
                  onClick={handleGenerateVideo}
                  disabled={isGeneratingVideo || !uploadedImage || !activeSong}
                  className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black uppercase tracking-[0.2em] text-xs hover:bg-indigo-500 disabled:opacity-40 transition-all flex items-center justify-center gap-3"
                >
                  {isGeneratingVideo ? <Loader2 className="animate-spin" size={18} /> : <Video size={18} />}
                  {isGeneratingVideo ? 'Synthesizing Video...' : 'Animate with Veo'}
                </button>

                {videoUrl && (
                  <div className="space-y-4 animate-in zoom-in-95 pt-4 border-t border-zinc-900">
                     <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 ml-1">Generated Output</label>
                     <video src={videoUrl} controls className="w-full rounded-2xl shadow-2xl border border-zinc-800" />
                  </div>
                )}
             </div>
          </div>
        )}

        {sidebarView === 'library' && (
          <div className="p-7 space-y-6">
            <h2 className="text-2xl font-black tracking-tight uppercase italic">Session Library</h2>
            {library.length === 0 ? (
              <p className="text-zinc-600 text-[10px] font-black uppercase text-center py-10 tracking-[0.3em]">No saved sessions</p>
            ) : library.map(song => (
              <button 
                key={song.id}
                onClick={() => setActiveSong(song)}
                className={`w-full text-left p-4 rounded-2xl border transition-all flex items-center gap-4 group ${activeSong?.id === song.id ? 'bg-zinc-800/80 border-zinc-700' : 'bg-zinc-900/20 border-zinc-900 hover:border-zinc-800'}`}
              >
                <div className="w-10 h-10 bg-zinc-900 rounded-xl flex items-center justify-center group-hover:bg-zinc-800 border border-zinc-800">
                  <Music2 size={16} className="text-pink-500" />
                </div>
                <div className="flex-1 overflow-hidden">
                  <h4 className="font-black truncate text-sm tracking-tight">{song.title}</h4>
                  <div className="text-[9px] text-zinc-600 font-black uppercase tracking-widest italic">{song.genre} • {song.key}</div>
                </div>
              </button>
            ))}
          </div>
        )}
      </aside>

      <main className="flex-1 flex flex-col bg-[#020202]">
        {activeSong ? (
          <div className="flex-1 flex flex-col overflow-hidden">
            <div className="h-20 border-b border-zinc-900 flex items-center px-10 justify-between bg-zinc-950/40 backdrop-blur-2xl">
              <div className="flex items-center gap-8">
                <button 
                  onClick={isPlaying ? stopAll : () => playAll(tracks)}
                  className={`flex items-center gap-4 px-10 py-3.5 rounded-full font-black text-xs uppercase tracking-[0.3em] transition-all active:scale-95 shadow-2xl ${isPlaying ? 'bg-white text-black' : 'bg-indigo-600 text-white shadow-indigo-600/30 hover:bg-indigo-500'}`}
                >
                  {isPlaying ? <Square size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" />}
                  {isPlaying ? 'Stop Session' : 'Start Playback'}
                </button>

                <div className="flex items-center gap-8 bg-zinc-900/30 px-8 py-3 rounded-2xl border border-zinc-800/50 shadow-inner">
                   <div className="flex flex-col">
                     <span className="text-[8px] font-black uppercase text-zinc-600 tracking-widest mb-1 text-center">Tempo</span>
                     <span className="text-pink-500 font-black mono text-sm leading-none">{activeSong.bpm}</span>
                   </div>
                   <div className="w-px h-6 bg-zinc-800" />
                   <div className="flex flex-col">
                     <span className="text-[8px] font-black uppercase text-zinc-600 tracking-widest mb-1 text-center">Scale</span>
                     <span className="text-white font-black text-sm leading-none">{activeSong.key}</span>
                   </div>
                   <div className="w-px h-6 bg-zinc-800" />
                   <div className="flex items-center gap-3">
                      <Sparkles size={16} className="text-emerald-500" />
                      <span className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Master Saturation Live</span>
                   </div>
                </div>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-10 custom-scrollbar bg-[radial-gradient(circle_at_top,_#0a0a1a,_transparent)]">
              <div className="mb-12">
                <h1 className="text-7xl font-black tracking-tighter mb-4 italic bg-clip-text text-transparent bg-gradient-to-r from-white via-zinc-400 to-zinc-700">{activeSong.title}</h1>
                <p className="text-zinc-600 font-black uppercase tracking-[0.8em] text-[10px] ml-1">High-Fidelity Multi-Track Logic • Pro Dynamic Simulation</p>
              </div>

              <div className="grid grid-cols-1 gap-6">
                {tracks.map(track => (
                  <div key={track.id} className="flex gap-8 items-center bg-zinc-950/40 p-3 pr-10 rounded-[2.5rem] border border-zinc-900/80 hover:border-zinc-700 transition-all group relative overflow-hidden">
                    <div className="w-56 p-5 flex flex-col gap-4 z-10 border-r border-zinc-900/50">
                      <div className="flex items-center gap-4">
                        <div className="w-4 h-4 rounded-full shadow-[0_0_15px_currentColor]" style={{ color: track.color, backgroundColor: 'currentColor' }} />
                        <span className="font-black uppercase tracking-[0.2em] text-[11px] text-zinc-300 truncate">{track.name}</span>
                      </div>
                      <div className="flex gap-2">
                        <button onClick={() => handleUpdateTrack(track.id, { isMuted: !track.isMuted })} className={`text-[10px] font-black px-4 py-2 rounded-xl border transition-all ${track.isMuted ? 'bg-red-600 border-red-500 text-white' : 'bg-zinc-900/60 border-zinc-800 text-zinc-500 hover:text-zinc-300'}`}>MUTE</button>
                        <button onClick={() => handleUpdateTrack(track.id, { isSolo: !track.isSolo })} className={`text-[10px] font-black px-4 py-2 rounded-xl border transition-all ${track.isSolo ? 'bg-yellow-500 border-yellow-400 text-zinc-950' : 'bg-zinc-900/60 border-zinc-800 text-zinc-500 hover:text-zinc-300'}`}>SOLO</button>
                      </div>
                    </div>

                    <div className="flex-1 h-24 bg-black/60 rounded-[2rem] border border-zinc-900/50 overflow-hidden relative shadow-inner">
                       <Waveform color={track.color} intensity={track.buffer ? 1 : 0.1} isPlaying={isPlaying && !track.isMuted} height={96} />
                       <div className="absolute top-2 right-6 text-[8px] font-black text-zinc-800 tracking-[0.4em] uppercase flex items-center gap-2">
                          PCM STREAM RAW_2.5
                          {track.sidechainSourceId && <span className="text-indigo-400 flex items-center gap-1"><Link2 size={8}/> DUCKING</span>}
                       </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="h-96 border-t border-zinc-900 bg-[#050505]/95 backdrop-blur-3xl p-10 flex gap-8 overflow-x-auto custom-scrollbar items-end shadow-2xl relative">
               <div className="absolute top-4 left-1/2 -translate-x-1/2 text-[10px] font-black text-zinc-800 tracking-[1em] uppercase pointer-events-none">Virtual Mixing Console v2.5</div>
               {tracks.map(track => (
                 <MixerTrack key={track.id} track={track} allTracks={tracks} onUpdate={handleUpdateTrack} isPlaying={isPlaying} />
               ))}
               <div className="flex flex-col items-center bg-zinc-900/40 rounded-[2rem] p-8 w-40 border-2 border-zinc-800/50 ml-auto h-full justify-between shadow-2xl relative">
                <Volume2 size={24} className="text-zinc-600 mt-4" />
                <div className="flex-1 w-full flex justify-center py-8 relative">
                   <div className="w-1.5 bg-zinc-800 h-full absolute rounded-full shadow-inner" />
                   <div className="absolute bottom-10 w-2.5 bg-gradient-to-t from-pink-600 via-indigo-600 to-indigo-400 h-2/3 rounded-full blur-[3px] opacity-40 shadow-[0_0_30px_#4f46e5]" />
                   <input 
                    type="range" 
                    min="0"
                    max="1.5"
                    step="0.01"
                    value={masterGainValue}
                    onChange={(e) => setMasterGainValue(parseFloat(e.target.value))}
                    className="appearance-none bg-transparent w-48 -rotate-90 absolute top-1/2 cursor-pointer fader-range" 
                   />
                </div>
                <span className="text-[11px] font-black text-zinc-300 uppercase italic tracking-widest">MASTER OUT</span>
               </div>
            </div>
          </div>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center p-16 text-center">
            <div className="relative mb-12">
               <div className="absolute inset-0 bg-pink-500 blur-[100px] opacity-10 animate-pulse" />
               <Disc className="text-zinc-900 animate-spin-slow relative" size={180} />
               <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-pink-600" size={56} />
            </div>
            <h2 className="text-6xl font-black tracking-tighter mb-6 uppercase italic text-transparent bg-clip-text bg-gradient-to-b from-white to-zinc-800">Aether Engine V2</h2>
            <p className="text-zinc-600 max-w-md mx-auto mb-12 text-sm font-black uppercase tracking-[0.4em] leading-relaxed">
              Multi-Stem Synthesis • Pro Dynamic Phrasing • Veo Visual Integration
            </p>
            <button onClick={() => setSidebarView('create')} className="bg-white text-black px-16 py-6 rounded-[2rem] font-black text-xs uppercase tracking-[0.4em] flex items-center gap-5 hover:scale-105 transition-all shadow-2xl group active:scale-95">
              <Zap size={24} className="group-hover:rotate-12 transition-transform text-indigo-600" /> Start Band Session
            </button>
          </div>
        )}
      </main>

      {isGenerating && (
        <div className="fixed inset-0 bg-black/99 backdrop-blur-3xl z-[100] flex flex-col items-center justify-center">
           <Disc className="text-pink-600 animate-spin-slow mb-12 shadow-[0_0_120px_#db277720]" size={120} />
           <div className="flex flex-col items-center gap-4">
             <h2 className="text-4xl font-black tracking-tighter uppercase italic text-transparent bg-clip-text bg-gradient-to-r from-white via-pink-500 to-indigo-600 animate-pulse">
               {generationStep}
             </h2>
             <div className="h-1.5 w-80 bg-zinc-900 rounded-full mt-6 overflow-hidden border border-zinc-800">
                <div className="h-full bg-pink-600 animate-shimmer w-1/3 shadow-[0_0_15px_#db2777]" />
             </div>
             <p className="mt-4 text-zinc-700 font-black uppercase tracking-[0.8em] text-[10px]">Processing Multi-Stem Nuance Data</p>
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 5px; height: 5px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #222; border-radius: 10px; }
        @keyframes spin-slow { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .animate-spin-slow { animation: spin-slow 15s linear infinite; }
        @keyframes shimmer { 0% { transform: translateX(-100%); } 100% { transform: translateX(300%); } }
        .animate-shimmer { animation: shimmer 1.5s infinite ease-in-out; }
        .fader-range { -webkit-appearance: none; }
        .fader-range::-webkit-slider-thumb { 
          -webkit-appearance: none; 
          width: 24px; height: 36px; 
          background: #eee; 
          border-radius: 4px; 
          cursor: pointer; 
          border: 1px solid #999;
          box-shadow: 0 4px 10px rgba(0,0,0,0.5);
        }
      `}</style>
    </div>
  );
};

export default App;
